import{D as e,d as t,l as n}from"./runtime-core.esm-bundler-BkUJkfAY.js";import{t as r}from"./plugin-vue_export-helper-CwH_LPhl.js";var i=JSON.parse(`{"path":"/%E9%9D%A2%E8%AF%95%E9%A2%98/%E5%90%8E%E7%AB%AF%E9%9D%A2%E8%AF%95%E9%A2%98/03.%E4%B8%AD%E7%BA%A7.html","title":"中级","lang":"zh-CN","frontmatter":{"title":"中级","date":"2026-02-06T11:51:53.000Z","category":["后端","C#"],"tag":["中级 底层"],"author":"Mokylp","order":3},"git":{"createdTime":1775202256000,"updatedTime":1775203190000,"contributors":[{"name":"moklgy","username":"moklgy","email":"moklgy@foxmail.com","commits":2,"url":"https://github.com/moklgy"}]},"readingTime":{"minutes":60.21,"words":18063},"filePathRelative":"面试题/后端面试题/03.中级.md","excerpt":"<h2>🟡 中级梯队：C# 高级特性与内存管理（1–30）</h2>\\n<h3>1）async/await 状态机详解</h3>\\n<p><strong>面试官：</strong> <code>async</code> 方法编译后变成了什么？状态机是怎么工作的？<br>\\n<strong>候选人（要点）：</strong> 编译器生成一个实现 <code>IAsyncStateMachine</code> 的结构体，把方法拆成多个状态节点；<code>await</code> 点保存上下文（局部变量、执行位置）并注册 continuation；IO 完成后由线程池线程调用 <code>MoveNext()</code> 恢复执行。[3][4]<br>\\n<strong>面试官追问：</strong> 如果 <code>await</code> 的 Task 已经是完成状态（同步完成），还会发生线程切换吗？这种情况下 <code>ValueTask</code> 有什么优势？</p>"}`),a={name:`03.中级.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h2 id="🟡-中级梯队-c-高级特性与内存管理-1–30" tabindex="-1"><a class="header-anchor" href="#🟡-中级梯队-c-高级特性与内存管理-1–30"><span>🟡 中级梯队：C# 高级特性与内存管理（1–30）</span></a></h2><h3 id="_1-async-await-状态机详解" tabindex="-1"><a class="header-anchor" href="#_1-async-await-状态机详解"><span>1）async/await 状态机详解</span></a></h3><p><strong>面试官：</strong> <code>async</code> 方法编译后变成了什么？状态机是怎么工作的？<br><strong>候选人（要点）：</strong> 编译器生成一个实现 <code>IAsyncStateMachine</code> 的结构体，把方法拆成多个状态节点；<code>await</code> 点保存上下文（局部变量、执行位置）并注册 continuation；IO 完成后由线程池线程调用 <code>MoveNext()</code> 恢复执行。[3][4]<br><strong>面试官追问：</strong> 如果 <code>await</code> 的 Task 已经是完成状态（同步完成），还会发生线程切换吗？这种情况下 <code>ValueTask</code> 有什么优势？</p><h3 id="_2-configureawait-false-深度" tabindex="-1"><a class="header-anchor" href="#_2-configureawait-false-深度"><span>2）ConfigureAwait(false) 深度</span></a></h3><p><strong>面试官：</strong> <code>ConfigureAwait(false)</code> 到底在做什么？<a href="http://ASP.NET" target="_blank" rel="noopener noreferrer">ASP.NET</a> Core 里还需要写它吗？<br><strong>候选人（要点）：</strong> 它告诉状态机不要强制恢复到原来的同步上下文；在 Core 里默认没有 <code>SynchronizationContext</code>，所以通常不强制要求，但在库代码里写上更安全（避免在某些宿主环境下死锁）。<br><strong>面试官追问：</strong> WinForms/WPF 里不写会怎样？为什么 UI 线程会死锁？你能画出死锁的调用链吗？</p><h3 id="_3-task-run-vs-task-factory-startnew" tabindex="-1"><a class="header-anchor" href="#_3-task-run-vs-task-factory-startnew"><span>3）Task.Run vs Task.Factory.StartNew</span></a></h3><p><strong>面试官：</strong> <code>Task.Run</code> 和 <code>Task.Factory.StartNew</code> 区别？什么时候必须用后者？<br><strong>候选人（要点）：</strong> <code>Task.Run</code> 是简化 API，固定用线程池并默认 <code>DenyChildAttach</code>；<code>StartNew</code> 可指定调度器、支持父子任务附加等高级场景。通常推荐 <code>Task.Run</code>，除非需要精细控制任务层级或自定义 TaskScheduler。<br><strong>面试官追问：</strong> 父子任务附加（AttachedToParent）有什么用？不显式指定会有什么坑？</p><h3 id="_4-cancellationtoken-最佳实践" tabindex="-1"><a class="header-anchor" href="#_4-cancellationtoken-最佳实践"><span>4）CancellationToken 最佳实践</span></a></h3><p><strong>面试官：</strong> <code>CancellationToken</code> 怎么用？不传会怎样？<br><strong>候选人（要点）：</strong> Token 用于优雅取消异步操作；不传会导致任务无法及时停止、资源浪费、超时堆积。<br><strong>面试官追问：</strong> 如果你的 <code>async</code> 方法里调了第三方库且它不接受 Token，你怎么做超时控制？<code>Task.WhenAny</code> + <code>Task.Delay</code> 的坑是什么？</p><h3 id="_5-synchronizationcontext-深度" tabindex="-1"><a class="header-anchor" href="#_5-synchronizationcontext-深度"><span>5）SynchronizationContext 深度</span></a></h3><p><strong>面试官：</strong> 什么是 <code>SynchronizationContext</code>？为什么 <a href="http://ASP.NET" target="_blank" rel="noopener noreferrer">ASP.NET</a> Core 去掉了它？<br><strong>候选人（要点）：</strong> 它是&quot;上下文切换抽象&quot;，让 <code>await</code> 后能回到特定上下文（UI 线程/ASP.NET 请求上下文）。Core 去掉是为了性能：避免不必要的线程切换与队列调度，任何线程池线程都可以继续执行。[5]<br><strong>面试官追问：</strong> 这对异常传播有什么影响？为什么 Core 里 <code>async void</code> 异常处理更危险？</p><h3 id="_6-gc-深度-分代与提升" tabindex="-1"><a class="header-anchor" href="#_6-gc-深度-分代与提升"><span>6）GC 深度：分代与提升</span></a></h3><p><strong>面试官：</strong> 什么情况下对象会从 Gen 0 提升到 Gen 1？Gen 2 回收为什么慢？<br><strong>候选人（要点）：</strong> Gen 0 GC 后存活的对象提升到 Gen 1；Gen 2 扫描范围大且可能触发 Full GC（包括 LOH），导致 STW 时间长。[6]<br><strong>面试官追问：</strong> 大对象（85KB+）为什么直接进 LOH？LOH 的碎片问题怎么缓解？</p><h3 id="_7-span-与-memory-深度" tabindex="-1"><a class="header-anchor" href="#_7-span-与-memory-深度"><span>7）Span 与 Memory 深度</span></a></h3><p><strong>面试官：</strong> <code>Span&lt;T&gt;</code> 为什么不能跨 <code>await</code>？<code>Memory&lt;T&gt;</code> 解决了什么问题？<br><strong>候选人（要点）：</strong> <code>Span&lt;T&gt;</code> 是 ref struct，只能在栈上（避免逃逸到堆），编译器禁止跨异步边界；<code>Memory&lt;T&gt;</code> 是普通 struct 但包含对象引用，可以跨 await，适合异步 IO 场景。<br><strong>面试官追问：</strong> 什么场景下你必须用 <code>Span</code>？如果在高频字符串解析里怎么利用它避免 <code>Substring</code> 分配？</p><h3 id="_8-arraypool-实战" tabindex="-1"><a class="header-anchor" href="#_8-arraypool-实战"><span>8）ArrayPool 实战</span></a></h3><p><strong>面试官：</strong> <code>ArrayPool&lt;T&gt;</code> 什么时候用？租还时有什么坑？<br><strong>候选人（要点）：</strong> 用于复用大数组（避免 LOH 压力），特别是临时缓冲区；租还必须成对且不能在归还后继续使用，否则会出现&quot;数据被别人覆盖&quot;的诡异 bug。<br><strong>面试官追问：</strong> 租到的数组内容是干净的吗？什么时候需要手动清零？</p><h3 id="_9-weak-reference-弱引用" tabindex="-1"><a class="header-anchor" href="#_9-weak-reference-弱引用"><span>9）weak reference（弱引用）</span></a></h3><p><strong>面试官：</strong> 什么是弱引用？你在什么场景用过？<br><strong>候选人（要点）：</strong> 弱引用允许 GC 在需要时回收对象，即使引用还在；适合缓存、订阅清理等&quot;可失去&quot;的场景。<br><strong>面试官追问：</strong> 弱引用能防内存泄漏吗？事件订阅为什么还是要显式取消订阅？</p><h3 id="_10-finalizer-与-gc-压力" tabindex="-1"><a class="header-anchor" href="#_10-finalizer-与-gc-压力"><span>10）finalizer 与 GC 压力</span></a></h3><p><strong>面试官：</strong> Finalizer（析构函数）会让对象经历几次 GC？为什么说它增加 GC 压力？<br><strong>候选人（要点）：</strong> 有 Finalizer 的对象至少两次：第一次进入 finalization queue，Finalizer 线程执行后第二次才真正回收。Finalizer 还会拖慢提升速度、增加 Gen 2 扫描成本。<br><strong>面试官追问：</strong> <code>SafeHandle</code> 为什么比手写 Finalizer 更好？它的实现原理是什么？</p><h3 id="_11-record-类型深度" tabindex="-1"><a class="header-anchor" href="#_11-record-类型深度"><span>11）record 类型深度</span></a></h3><p><strong>面试官：</strong> C# 9 的 <code>record</code> 本质是什么？它和 <code>class</code> / <code>struct</code> 有什么区别？<br><strong>候选人（要点）：</strong> <code>record</code> 是引用类型但具有值语义（基于内容的相等性、with 表达式生成副本），适合不可变数据传输对象（DTO）。<br><strong>面试官追问：</strong> <code>record struct</code> 和普通 <code>struct</code> 区别？什么时候 <code>record</code> 不适合（如大对象频繁拷贝）？</p><h3 id="_12-primary-constructor-主构造函数" tabindex="-1"><a class="header-anchor" href="#_12-primary-constructor-主构造函数"><span>12）Primary Constructor（主构造函数）</span></a></h3><p><strong>面试官：</strong> C# 12 的主构造函数有什么用？它和传统构造函数的区别？<br><strong>候选人（要点）：</strong> 减少样板代码，参数作为隐式字段捕获；适合简单依赖注入场景。<br><strong>面试官追问：</strong> 主构造函数的参数作用域是整个类，这会不会导致闭包陷阱（比如在方法里访问已经过期的参数）？</p><h3 id="_13-nullable-reference-types-深度" tabindex="-1"><a class="header-anchor" href="#_13-nullable-reference-types-深度"><span>13）Nullable Reference Types 深度</span></a></h3><p><strong>面试官：</strong> <code>#nullable enable</code> 做了什么？它能真正防止 <code>NullReferenceException</code> 吗？<br><strong>候选人（要点）：</strong> 编译期静态分析，给出警告/错误；运行时仍可能空引用（因为反序列化、反射、外部库等绕过检查）。<br><strong>面试官追问：</strong> <code>!</code> 强制非空操作符滥用会怎样？怎么在旧代码库渐进式启用 nullable？</p><h3 id="_14-pattern-matching-深度" tabindex="-1"><a class="header-anchor" href="#_14-pattern-matching-深度"><span>14）Pattern Matching 深度</span></a></h3><p><strong>面试官：</strong> 模式匹配（Pattern Matching）有什么实际价值？给一个替代 <code>if-else</code> 的例子。<br><strong>候选人（要点）：</strong> 简化类型判断与属性解构，提升可读性；例如 <code>obj switch { Student s when s.Age &gt; 18 =&gt; ..., Teacher =&gt; ... }</code>。<br><strong>面试官追问：</strong> 编译器如何优化 switch 表达式？它和传统 switch 在 IL 层面有什么不同？</p><h3 id="_15-expression-tree-表达式树-实战" tabindex="-1"><a class="header-anchor" href="#_15-expression-tree-表达式树-实战"><span>15）Expression Tree（表达式树）实战</span></a></h3><p><strong>面试官：</strong> 表达式树在 EF Core 里的作用？为什么它能翻译成 SQL？<br><strong>候选人（要点）：</strong> 表达式树把代码表示为数据结构（AST），Provider 遍历并生成 SQL；这是 LINQ to SQL/EF 的基石。<br><strong>面试官追问：</strong> 你能手写一个简单的表达式树并编译成委托吗？Visitor 模式怎么遍历表达式树？</p><h3 id="_16-reflection-性能坑" tabindex="-1"><a class="header-anchor" href="#_16-reflection-性能坑"><span>16）Reflection 性能坑</span></a></h3><p><strong>面试官：</strong> 反射为什么慢？你会怎么优化频繁反射调用？<br><strong>候选人（要点）：</strong> 反射慢在元数据查找、权限检查、装箱拆箱、动态调用；优化手段包括缓存 <code>MethodInfo</code>、编译表达式树为委托、使用 <code>DynamicMethod</code> / Emit 生成代码。<br><strong>面试官追问：</strong> <code>Activator.CreateInstance</code> vs <code>Expression.New</code> 编译的委托，性能差多少？</p><h3 id="_17-idisposable-模式完整版" tabindex="-1"><a class="header-anchor" href="#_17-idisposable-模式完整版"><span>17）IDisposable 模式完整版</span></a></h3><p><strong>面试官：</strong> 标准的 <code>Dispose</code> 模式是怎样的？为什么要写 <code>Dispose(bool disposing)</code>？<br><strong>候选人（要点）：</strong> 支持子类继承重写、区分&quot;用户显式调用&quot;与&quot;Finalizer 调用&quot;；<code>disposing=true</code> 时可释放托管资源，<code>false</code> 时只释放非托管。<br><strong>面试官追问：</strong> <code>IAsyncDisposable</code> 什么时候用？异步 <code>Dispose</code> 里抛异常会怎样？</p><h3 id="_18-interlocked-与原子操作" tabindex="-1"><a class="header-anchor" href="#_18-interlocked-与原子操作"><span>18）Interlocked 与原子操作</span></a></h3><p><strong>面试官：</strong> <code>Interlocked</code> 类是干什么的？为什么它比 <code>lock</code> 快？<br><strong>候选人（要点）：</strong> 提供原子操作（CAS/Compare-And-Swap），无需进入内核态或获取锁，适合简单的计数/标志位。<br><strong>面试官追问：</strong> <code>Interlocked.Increment</code> 能保证可见性吗？volatile 和 Interlocked 的关系？</p><h3 id="_19-volatile-关键字深度" tabindex="-1"><a class="header-anchor" href="#_19-volatile-关键字深度"><span>19）volatile 关键字深度</span></a></h3><p><strong>面试官：</strong> <code>volatile</code> 到底做了什么？它能防止指令重排吗？<br><strong>候选人（要点）：</strong> <code>volatile</code> 保证读写的内存屏障，防止编译器/CPU 重排序并保证可见性；但它不保证原子性（复合操作仍需锁/Interlocked）。<br><strong>面试官追问：</strong> 双重检查锁定（DCL）为什么需要 volatile？不加会出现什么诡异 bug？</p><h3 id="_20-threadlocal-场景" tabindex="-1"><a class="header-anchor" href="#_20-threadlocal-场景"><span>20）ThreadLocal 场景</span></a></h3><p><strong>面试官：</strong> <code>ThreadLocal&lt;T&gt;</code> 是做什么的？你在什么场景用它？<br><strong>候选人（要点）：</strong> 每个线程独立存储一份副本，避免共享状态竞争；常用于日志上下文、随机数生成器、非线程安全对象池化。<br><strong>面试官追问：</strong> 异步代码里用 <code>ThreadLocal</code> 有什么坑（线程池线程复用导致上下文混乱）？<code>AsyncLocal&lt;T&gt;</code> 解决了什么？</p><h3 id="_21-线程池调优" tabindex="-1"><a class="header-anchor" href="#_21-线程池调优"><span>21）线程池调优</span></a></h3><p><strong>面试官：</strong> 线程池的最小/最大线程数怎么调？什么情况下需要手动调？<br><strong>候选人（要点）：</strong> 默认最小值通常等于 CPU 核数，最大值很大；如果有大量同步阻塞操作（如同步 IO），可能需要提高最小线程数避免饥饿；异步场景通常不需要调。<br><strong>面试官追问：</strong> 线程池饥饿（Thread Pool Starvation）是什么？怎么从监控指标里发现？</p><h3 id="_22-parallel-foreach-深度" tabindex="-1"><a class="header-anchor" href="#_22-parallel-foreach-深度"><span>22）Parallel.ForEach 深度</span></a></h3><p><strong>面试官：</strong> <code>Parallel.ForEach</code> 什么时候比普通 <code>foreach</code> 快？什么时候反而更慢？<br><strong>候选人（要点）：</strong> CPU 密集、可并行、无共享状态时快；如果单次迭代极快或有锁竞争，调度开销反而拖累性能。<br><strong>面试官追问：</strong> 怎么控制并行度（<code>MaxDegreeOfParallelism</code>）？并行里抛异常会怎样？</p><h3 id="_23-channels-system-threading-channels" tabindex="-1"><a class="header-anchor" href="#_23-channels-system-threading-channels"><span>23）Channels (System.Threading.Channels)</span></a></h3><p><strong>面试官：</strong> <code>Channel&lt;T&gt;</code> 是做什么的？为什么比 <code>BlockingCollection</code> 更好？<br><strong>候选人（要点）：</strong> 高性能异步生产者-消费者队列，支持背压、限流；比 <code>BlockingCollection</code> 更轻量且对异步友好。<br><strong>面试官追问：</strong> Bounded vs Unbounded Channel？生产者比消费者快时怎么处理背压？</p><h3 id="_24-task-vs-thread" tabindex="-1"><a class="header-anchor" href="#_24-task-vs-thread"><span>24）Task vs Thread</span></a></h3><p><strong>面试官：</strong> <code>Task</code> 和 <code>Thread</code> 本质区别？为什么不推荐直接 <code>new Thread</code>？<br><strong>候选人（要点）：</strong> <code>Task</code> 是轻量异步工作单元，基于线程池调度；<code>Thread</code> 是重量级 OS 线程，创建销毁成本高且难管理。<br><strong>面试官追问：</strong> 什么情况下你还是需要创建专用线程（如长时间运行、需要设置 ApartmentState）？</p><h3 id="_25-semaphoreslim-与限流" tabindex="-1"><a class="header-anchor" href="#_25-semaphoreslim-与限流"><span>25）SemaphoreSlim 与限流</span></a></h3><p><strong>面试官：</strong> <code>SemaphoreSlim</code> 是干什么的？你怎么用它做并发限流？<br><strong>候选人（要点）：</strong> 控制同时访问资源的线程数（如限制并发数据库连接）；通过 <code>WaitAsync</code> 实现异步等待。<br><strong>面试官追问：</strong> 忘记 <code>Release()</code> 会怎样？怎么保证异常时也能释放信号量？</p><h3 id="_26-lock-vs-monitor-vs-mutex" tabindex="-1"><a class="header-anchor" href="#_26-lock-vs-monitor-vs-mutex"><span>26）lock vs Monitor vs Mutex</span></a></h3><p><strong>面试官：</strong> <code>lock</code>、<code>Monitor</code>、<code>Mutex</code> 的区别？跨进程锁用哪个？<br><strong>候选人（要点）：</strong> <code>lock</code> 是 <code>Monitor</code> 的语法糖（进程内）；<code>Mutex</code> 支持跨进程但性能更差。<br><strong>面试官追问：</strong> <code>Monitor.TryEnter</code> 超时机制？死锁检测工具怎么用？</p><h3 id="_27-lazy-线程安全模式" tabindex="-1"><a class="header-anchor" href="#_27-lazy-线程安全模式"><span>27）Lazy 线程安全模式</span></a></h3><p><strong>面试官：</strong> <code>Lazy&lt;T&gt;</code> 的线程安全模式有哪几种？默认是哪个？<br><strong>候选人（要点）：</strong> <code>ExecutionAndPublication</code>（默认，最安全）、<code>PublicationOnly</code>、<code>None</code>；选择取决于初始化成本与并发需求。<br><strong>面试官追问：</strong> 如果初始化抛异常，<code>Lazy</code> 会缓存异常吗？后续访问会怎样？</p><h3 id="_28-immutablecollections-价值" tabindex="-1"><a class="header-anchor" href="#_28-immutablecollections-价值"><span>28）ImmutableCollections 价值</span></a></h3><p><strong>面试官：</strong> 不可变集合（<code>ImmutableList/Dictionary</code>）有什么用？性能不是更差吗？<br><strong>候选人（要点）：</strong> 适合多线程共享、版本控制、函数式编程；虽然写入慢（拷贝开销），但读并发安全且无锁。<br><strong>面试官追问：</strong> 内部实现是什么（持久化数据结构/平衡树）？什么时候不该用？</p><h3 id="_29-stringpool-intern" tabindex="-1"><a class="header-anchor" href="#_29-stringpool-intern"><span>29）StringPool / Intern</span></a></h3><p><strong>面试官：</strong> 字符串驻留池（Intern Pool）是什么？<code>String.Intern</code> 有什么坑？<br><strong>候选人（要点）：</strong> 池化相同字面量字符串避免重复分配；但 <code>Intern</code> 会让字符串进入 Gen 2 且不释放，滥用会内存泄漏。<br><strong>面试官追问：</strong> 什么场景适合 Intern（如固定枚举字符串）？什么场景禁止（用户输入）？</p><h3 id="_30-encoding-与字符集" tabindex="-1"><a class="header-anchor" href="#_30-encoding-与字符集"><span>30）Encoding 与字符集</span></a></h3><p><strong>面试官：</strong> UTF-8 / UTF-16 / GBK 的区别？.NET 内部字符串用什么编码？<br><strong>候选人（要点）：</strong> .NET <code>string</code> 内部是 UTF-16；跨系统通信常用 UTF-8（更紧凑）；转换不当会乱码或丢数据。<br><strong>面试官追问：</strong> <code>BOM</code>（字节顺序标记）是什么？什么时候需要、什么时候会坑？</p><h2 id="🟡-中级梯队-asp-net-core-高级特性与性能调优-31–60-1" tabindex="-1"><a class="header-anchor" href="#🟡-中级梯队-asp-net-core-高级特性与性能调优-31–60-1"><span>🟡 中级梯队：<a href="http://ASP.NET" target="_blank" rel="noopener noreferrer">ASP.NET</a> Core 高级特性与性能调优（31–60）[1]</span></a></h2><h3 id="_31-中间件短路与条件分支" tabindex="-1"><a class="header-anchor" href="#_31-中间件短路与条件分支"><span>31）中间件短路与条件分支</span></a></h3><p><strong>面试官：</strong> 中间件里不调用 <code>next()</code> 会怎样？给一个&quot;缓存中间件直接返回结果&quot;的例子。<br><strong>候选人（要点）：</strong> 短路管道，后续中间件与端点不会执行；缓存命中时可直接 <code>await context.Response.WriteAsync()</code> 并返回，节省后续计算。[2]<br><strong>面试官追问：</strong> 如果在短路前已经有中间件修改了 Response Header/Body，会有什么风险？怎么保证幂等性？</p><h3 id="_32-iapplicationbuilder-管道构建原理" tabindex="-1"><a class="header-anchor" href="#_32-iapplicationbuilder-管道构建原理"><span>32）IApplicationBuilder 管道构建原理</span></a></h3><p><strong>面试官：</strong> <code>IApplicationBuilder</code> 是怎么把中间件&quot;串&quot;起来的？用委托链还是其他？<br><strong>候选人（要点）：</strong> 通过委托链（<code>RequestDelegate</code>），每个中间件持有 <code>next</code>，调用 next 就是调用下一个委托；最终形成一个嵌套的 Func 链。[3]<br><strong>面试官追问：</strong> 如果某个中间件构造耗时很长，会阻塞启动吗？怎么做异步初始化？</p><h3 id="_33-endpoint-routing-深度" tabindex="-1"><a class="header-anchor" href="#_33-endpoint-routing-深度"><span>33）Endpoint Routing 深度</span></a></h3><p><strong>面试官：</strong> <code>UseRouting</code> 和 <code>UseEndpoints</code> 为什么要分开？中间放鉴权的意义？<br><strong>候选人（要点）：</strong> <code>UseRouting</code> 只做路由匹配与选择端点，<code>UseEndpoints</code> 执行端点；分离后可以在中间插入认证/授权中间件，基于路由元数据做决策。<br><strong>面试官追问：</strong> 如果 <code>UseAuthentication</code> 放在 <code>UseRouting</code> 之前会怎样？路由匹配能拿到认证信息吗？</p><h3 id="_34-filter-执行顺序与作用域" tabindex="-1"><a class="header-anchor" href="#_34-filter-执行顺序与作用域"><span>34）Filter 执行顺序与作用域</span></a></h3><p><strong>面试官：</strong> Authorization / Resource / Action / Exception / Result Filter 的执行顺序？哪个能短路？<br><strong>候选人（要点）：</strong> Authorization 最早（可短路），Resource 可做缓存（可短路），Action 在执行前后，Exception 捕获异常，Result 在返回前后。<br><strong>面试官追问：</strong> 如果在 Action Filter 里修改了 <code>ActionExecutingContext.Result</code>，后续会怎样？</p><h3 id="_35-全局异常处理-middleware-vs-filter" tabindex="-1"><a class="header-anchor" href="#_35-全局异常处理-middleware-vs-filter"><span>35）全局异常处理：Middleware vs Filter</span></a></h3><p><strong>面试官：</strong> 全局异常用中间件还是过滤器？各自优缺点？<br><strong>候选人（要点）：</strong> 中间件能捕获整个管道（包括静态文件、路由错误），过滤器只在 MVC 管道内；中间件更通用，过滤器能访问 MVC 上下文（如 ModelState）。[4]<br><strong>面试官追问：</strong> 如果异常发生在 Response 已经开始写入后（如流式传输），怎么处理？</p><h3 id="_36-模型绑定深度" tabindex="-1"><a class="header-anchor" href="#_36-模型绑定深度"><span>36）模型绑定深度</span></a></h3><p><strong>面试官：</strong> 模型绑定的优先级（Body/Query/Route/Form）？如何自定义 Model Binder？<br><strong>候选人（要点）：</strong> <code>[ApiController]</code> 会自动推断（复杂类型走 Body，简单类型走 Query/Route）；自定义 Binder 实现 <code>IModelBinder</code> 并注册到 <code>ModelBinderProviders</code>。<br><strong>面试官追问：</strong> 绑定失败但没有验证错误，怎么调试？<code>BindingSource</code> 元数据有什么用？</p><h3 id="_37-模型验证与-fluentvalidation" tabindex="-1"><a class="header-anchor" href="#_37-模型验证与-fluentvalidation"><span>37）模型验证与 FluentValidation</span></a></h3><p><strong>面试官：</strong> DataAnnotations 验证的局限性？为什么很多项目用 FluentValidation？<br><strong>候选人（要点）：</strong> DataAnnotations 耦合在实体上、表达能力有限、难测试；FluentValidation 分离验证逻辑、支持复杂规则与依赖注入、更易测试。<br><strong>面试官追问：</strong> FluentValidation 的异步验证规则（如查库验证唯一性）有什么性能风险？</p><h3 id="_38-ioptions-模式深度" tabindex="-1"><a class="header-anchor" href="#_38-ioptions-模式深度"><span>38）IOptions 模式深度</span></a></h3><p><strong>面试官：</strong> <code>IOptions&lt;T&gt;</code>、<code>IOptionsSnapshot&lt;T&gt;</code>、<code>IOptionsMonitor&lt;T&gt;</code> 分别适合什么生命周期的服务？<br><strong>候选人（要点）：</strong> <code>IOptions</code> 适合 Singleton（只读一次），<code>Snapshot</code> 适合 Scoped（每次请求刷新），<code>Monitor</code> 适合需要变更通知的场景（如配置热更新）。<br><strong>面试官追问：</strong> <code>IOptionsMonitor.OnChange</code> 回调在什么线程执行？并发安全吗？</p><h3 id="_39-配置源优先级与覆盖" tabindex="-1"><a class="header-anchor" href="#_39-配置源优先级与覆盖"><span>39）配置源优先级与覆盖</span></a></h3><p><strong>面试官：</strong> appsettings.json / 环境变量 / 命令行参数的优先级？怎么做敏感配置管理？<br><strong>候选人（要点）：</strong> 后注册的源优先级更高（命令行 &gt; 环境变量 &gt; json）；敏感配置用 Azure Key Vault / AWS Secrets Manager / User Secrets（开发）。<br><strong>面试官追问：</strong> 配置变更后怎么让应用无缝重载（不重启）？哪些组件不支持热更新？</p><h3 id="_40-日志结构化与-serilog" tabindex="-1"><a class="header-anchor" href="#_40-日志结构化与-serilog"><span>40）日志结构化与 Serilog</span></a></h3><p><strong>面试官：</strong> 为什么推荐结构化日志？<code>{UserId}</code> 和 <code>$&quot;{UserId}&quot;</code> 的区别？<br><strong>候选人（要点）：</strong> 结构化日志可以按字段查询、聚合、告警；占位符 <code>{UserId}</code> 会被解析为属性，字符串插值会丢失语义。<br><strong>面试官追问：</strong> 日志量大时怎么优化性能（异步写入、采样、日志级别动态控制）？</p><h3 id="_41-kestrel-性能调优" tabindex="-1"><a class="header-anchor" href="#_41-kestrel-性能调优"><span>41）Kestrel 性能调优</span></a></h3><p><strong>面试官：</strong> Kestrel 的连接限制、请求超时、HTTP/2 配置在哪里设置？<br><strong>候选人（要点）：</strong> 在 <code>ConfigureKestrel</code> 中设置 <code>Limits</code>（如 <code>MaxConcurrentConnections</code>、<code>KeepAliveTimeout</code>）；HTTP/2 默认启用，注意客户端兼容性。<br><strong>面试官追问：</strong> 什么情况下需要调大 <code>MaxRequestBodySize</code>？调大有什么风险（DoS）？</p><h3 id="_42-响应压缩" tabindex="-1"><a class="header-anchor" href="#_42-响应压缩"><span>42）响应压缩</span></a></h3><p><strong>面试官：</strong> 响应压缩中间件（<code>UseResponseCompression</code>）默认压什么？动态内容会压吗？<br><strong>候选人（要点）：</strong> 默认压 <code>text/*</code> 和 <code>application/json</code> 等 MIME 类型；动态内容会压，但要注意 CPU 成本与延迟。<br><strong>面试官追问：</strong> HTTPS 下压缩为什么有安全风险（CRIME/BREACH 攻击）？怎么缓解？</p><h3 id="_43-cors-深度" tabindex="-1"><a class="header-anchor" href="#_43-cors-深度"><span>43）CORS 深度</span></a></h3><p><strong>面试官：</strong> CORS 预检请求（OPTIONS）什么时候触发？怎么优化预检成本？<br><strong>候选人（要点）：</strong> 非简单请求（如带自定义 Header、PUT/DELETE 方法）会触发预检；可通过 <code>Access-Control-Max-Age</code> 让浏览器缓存预检结果。<br><strong>面试官追问：</strong> <code>WithOrigins(&quot;*&quot;)</code> 和 <code>AllowAnyOrigin()</code> 有什么区别？为什么通配符不能和 <code>AllowCredentials</code> 共存？</p><h3 id="_44-健康检查-health-checks" tabindex="-1"><a class="header-anchor" href="#_44-健康检查-health-checks"><span>44）健康检查（Health Checks）</span></a></h3><p><strong>面试官：</strong> 健康检查怎么做？你会检查哪些依赖（DB/Redis/MQ）？<br><strong>候选人（要点）：</strong> 使用 <code>AddHealthChecks</code> 注册检查项，暴露端点（如 <code>/health</code>）供负载均衡/监控探测；检查关键依赖可用性。<br><strong>面试官追问：</strong> 健康检查失败但服务仍在运行，会发生什么？K8s 的 Readiness vs Liveness 探针区别？</p><h3 id="_45-静态文件与-cdn" tabindex="-1"><a class="header-anchor" href="#_45-静态文件与-cdn"><span>45）静态文件与 CDN</span></a></h3><p><strong>面试官：</strong> <code>UseStaticFiles</code> 做了什么？为什么生产环境要用 CDN？<br><strong>候选人（要点）：</strong> 中间件直接从 <code>wwwroot</code> 返回文件，短路后续管道；CDN 减少应用服务器带宽压力、提升全球访问速度、缓存边缘节点。<br><strong>面试官追问：</strong> 静态文件版本控制（缓存失效）怎么做？<code>asp-append-version</code> 的原理？</p><h3 id="_46-signalr-连接管理" tabindex="-1"><a class="header-anchor" href="#_46-signalr-连接管理"><span>46）SignalR 连接管理</span></a></h3><p><strong>面试官：</strong> SignalR 的传输协议（WebSocket/SSE/Long Polling）是怎么协商的？<br><strong>候选人（要点）：</strong> 客户端按优先级尝试，服务端根据支持情况选择最优；WebSocket 双向、低延迟，SSE 单向、简单，Long Polling 兜底。<br><strong>面试官追问：</strong> 横向扩展多实例时，SignalR 的消息怎么广播？Redis Backplane 原理？</p><h3 id="_47-授权策略-policy-based-authorization" tabindex="-1"><a class="header-anchor" href="#_47-授权策略-policy-based-authorization"><span>47）授权策略（Policy-Based Authorization）</span></a></h3><p><strong>面试官：</strong> 基于角色的授权 vs 基于策略的授权？给一个&quot;只有华东区经理能审核&quot;的策略。<br><strong>候选人（要点）：</strong> 角色授权简单但不灵活；策略授权可组合多种要求（角色+声明+自定义逻辑），实现细粒度控制。<br><strong>面试官追问：</strong> 如何在策略里访问数据库（依赖注入 DbContext）？异步授权处理器怎么写？</p><h3 id="_48-jwt-刷新令牌-refresh-token" tabindex="-1"><a class="header-anchor" href="#_48-jwt-刷新令牌-refresh-token"><span>48）JWT 刷新令牌（Refresh Token）</span></a></h3><p><strong>面试官：</strong> 为什么需要 Refresh Token？它和 Access Token 的生命周期设计？<br><strong>候选人（要点）：</strong> Access Token 短命（15分钟）减少泄露风险；Refresh Token 长命（天/周）存储在安全位置（HttpOnly Cookie），用于换取新 Access Token。<br><strong>面试官追问：</strong> Refresh Token 怎么做失效管理？被盗用怎么检测（Token Rotation/Family）？</p><h3 id="_49-rate-limiting-限流" tabindex="-1"><a class="header-anchor" href="#_49-rate-limiting-限流"><span>49）Rate Limiting（限流）</span></a></h3><p><strong>面试官：</strong> <a href="http://ASP.NET" target="_blank" rel="noopener noreferrer">ASP.NET</a> Core 7+ 内置的限流中间件怎么用？固定窗口 vs 滑动窗口？<br><strong>候选人（要点）：</strong> 使用 <code>AddRateLimiter</code> 注册策略；固定窗口简单但有突刺问题，滑动窗口更平滑但复杂。<br><strong>面试官追问：</strong> 分布式限流怎么做（Redis 计数器/令牌桶）？怎么区分&quot;按用户&quot;还是&quot;按IP&quot;？</p><h3 id="_50-输出缓存-output-caching" tabindex="-1"><a class="header-anchor" href="#_50-输出缓存-output-caching"><span>50）输出缓存（Output Caching）</span></a></h3><p><strong>面试官：</strong> 输出缓存和响应缓存的区别？什么场景适合用输出缓存？<br><strong>候选人（要点）：</strong> 输出缓存在服务端缓存完整响应（含 Header/Body），响应缓存靠 HTTP 缓存头让客户端/CDN 缓存；输出缓存适合昂贵计算的只读接口。<br><strong>面试官追问：</strong> 缓存 Key 怎么设计（按查询参数/用户/租户）？怎么做缓存失效（Tag-Based Invalidation）？</p><h3 id="_51-后台任务-hosted-service" tabindex="-1"><a class="header-anchor" href="#_51-后台任务-hosted-service"><span>51）后台任务（Hosted Service）</span></a></h3><p><strong>面试官：</strong> <code>IHostedService</code> 和 <code>BackgroundService</code> 的区别？怎么做定时任务？<br><strong>候选人（要点）：</strong> <code>BackgroundService</code> 是 <code>IHostedService</code> 的抽象基类，简化长时间运行任务；定时任务可用 <code>PeriodicTimer</code> 或第三方库（Hangfire/Quartz）。<br><strong>面试官追问：</strong> Hosted Service 里怎么正确使用 Scoped 服务（DbContext）？启动失败会影响应用启动吗？</p><h3 id="_52-grpc-深度" tabindex="-1"><a class="header-anchor" href="#_52-grpc-深度"><span>52）gRPC 深度</span></a></h3><p><strong>面试官：</strong> gRPC 相比 REST 的优势？什么场景适合用 gRPC？<br><strong>候选人（要点）：</strong> 二进制协议（Protobuf）更紧凑、强类型契约、双向流、性能更高；适合微服务内部通信、高吞吐低延迟场景。<br><strong>面试官追问：</strong> gRPC 在浏览器里能直接用吗？gRPC-Web 是什么？</p><h3 id="_53-minimal-api-vs-controller" tabindex="-1"><a class="header-anchor" href="#_53-minimal-api-vs-controller"><span>53）Minimal API vs Controller</span></a></h3><p><strong>面试官：</strong> Minimal API 的优缺点？什么项目适合用它？<br><strong>候选人（要点）：</strong> 优点是简洁、启动快、适合小项目/微服务；缺点是缺少 Controller 的约定（如模型绑定、过滤器）、可测试性稍差。<br><strong>面试官追问：</strong> Minimal API 里怎么做复杂的参数验证和全局错误处理？</p><h3 id="_54-httpclient-工厂模式" tabindex="-1"><a class="header-anchor" href="#_54-httpclient-工厂模式"><span>54）HttpClient 工厂模式</span></a></h3><p><strong>面试官：</strong> 为什么不能 <code>new HttpClient</code>？<code>IHttpClientFactory</code> 解决了什么问题？<br><strong>候选人（要点）：</strong> <code>new HttpClient</code> 会导致 Socket 耗尽和 DNS 不刷新；工厂模式复用 Handler 并管理连接池生命周期。<br><strong>面试官追问：</strong> Named Client vs Typed Client？怎么配置重试策略（Polly）？</p><h3 id="_55-请求-响应压缩与流式传输" tabindex="-1"><a class="header-anchor" href="#_55-请求-响应压缩与流式传输"><span>55）请求/响应压缩与流式传输</span></a></h3><p><strong>面试官：</strong> 大文件上传/下载怎么做流式传输？为什么不能全读到内存？<br><strong>候选人（要点）：</strong> 使用 <code>Stream</code> 分块读写，配合 <code>MultipartReader</code>（上传）或 <code>FileStreamResult</code>（下载）；全读内存会 OOM。<br><strong>面试官追问：</strong> 流式传输时怎么做进度报告？取消令牌怎么用？</p><h3 id="_56-api-版本控制" tabindex="-1"><a class="header-anchor" href="#_56-api-版本控制"><span>56）API 版本控制</span></a></h3><p><strong>面试官：</strong> API 版本控制有哪几种策略（URL/Header/Query）？你推荐哪种？<br><strong>候选人（要点）：</strong> URL 版本（<code>/api/v1/users</code>）最直观；Header 版本（<code>Api-Version</code>）更 RESTful；Query String 灵活但容易被忽略。<br><strong>面试官追问：</strong> 怎么做版本共存与向后兼容？怎么处理大版本升级的数据迁移？</p><h3 id="_57-请求日志与-traceid" tabindex="-1"><a class="header-anchor" href="#_57-请求日志与-traceid"><span>57）请求日志与 TraceId</span></a></h3><p><strong>面试官：</strong> 怎么在日志里关联同一个请求的所有日志？分布式追踪怎么做？<br><strong>候选人（要点）：</strong> 使用 <code>HttpContext.TraceIdentifier</code> 或 <code>Activity.TraceId</code>；分布式追踪靠传播 TraceId（如 W3C Trace Context Header）。<br><strong>面试官追问：</strong> OpenTelemetry 是什么？怎么集成到 <a href="http://ASP.NET" target="_blank" rel="noopener noreferrer">ASP.NET</a> Core？</p><h3 id="_58-内存缓存-imemorycache-深度" tabindex="-1"><a class="header-anchor" href="#_58-内存缓存-imemorycache-深度"><span>58）内存缓存（IMemoryCache）深度</span></a></h3><p><strong>面试官：</strong> <code>IMemoryCache</code> 怎么防止内存泄漏？绝对过期 vs 滑动过期？<br><strong>候选人（要点）：</strong> 设置 <code>Size</code> 和 <code>SizeLimit</code> 限制总内存；绝对过期是固定时间，滑动过期是&quot;最后访问后 X 时间&quot;（适合会话/热数据）。<br><strong>面试官追问：</strong> 并发访问同一个 Key 时，<code>GetOrCreate</code> 会重复计算吗？怎么保证只计算一次？</p><h3 id="_59-分布式缓存-idistributedcache" tabindex="-1"><a class="header-anchor" href="#_59-分布式缓存-idistributedcache"><span>59）分布式缓存（IDistributedCache）</span></a></h3><p><strong>面试官：</strong> <code>IDistributedCache</code> 抽象的好处？Redis vs SQL Server 分布式缓存？<br><strong>候选人（要点）：</strong> 抽象让实现可替换（开发用内存、生产用 Redis）；Redis 性能更好，SQL Server 适合已有基础设施且不想引入新组件的场景。<br><strong>面试官追问：</strong> 分布式缓存的一致性怎么保证？多实例同时写会怎样？</p><h3 id="_60-websockets-生命周期管理" tabindex="-1"><a class="header-anchor" href="#_60-websockets-生命周期管理"><span>60）WebSockets 生命周期管理</span></a></h3><p><strong>面试官：</strong> WebSocket 连接怎么管理？客户端断线怎么检测？<br><strong>候选人（要点）：</strong> 使用 <code>HttpContext.WebSockets.AcceptWebSocketAsync</code> 升级连接；通过心跳检测或读取超时判断断线。<br><strong>面试官追问：</strong> 长连接在负载均衡后怎么保持会话亲和性（Sticky Session）？水平扩展时怎么做消息广播？</p><hr><h2 id="🟡-中级梯队-ef-core-性能、数据库锁与高级查询-61–90-1" tabindex="-1"><a class="header-anchor" href="#🟡-中级梯队-ef-core-性能、数据库锁与高级查询-61–90-1"><span>🟡 中级梯队：EF Core 性能、数据库锁与高级查询（61–90）[1]</span></a></h2><h3 id="_61-n-1-进阶与-splitquery" tabindex="-1"><a class="header-anchor" href="#_61-n-1-进阶与-splitquery"><span>61）N+1 进阶与 SplitQuery</span></a></h3><p><strong>面试官：</strong> <code>SplitQuery</code> 到底是为了解决什么问题？它和普通 <code>Include</code> 的性能权衡点在哪？<br><strong>候选人（要点）：</strong> 普通 <code>Include</code> 产生笛卡尔积，数据冗余大；<code>SplitQuery</code> 拆成多条 SQL 避免冗余，但增加了数据库往返次数（RTT）。在&quot;主表少、子表多&quot;或&quot;子表包含大字段&quot;时，<code>SplitQuery</code> 性能更好；反之普通 <code>Include</code> 更好。[2]<br><strong>面试官追问：</strong> 如果 SplitQuery 执行了一半（比如第一条 SQL 成功，第二条失败），数据一致性怎么保证？</p><h3 id="_62-ef-core-批量操作-bulk-update-delete" tabindex="-1"><a class="header-anchor" href="#_62-ef-core-批量操作-bulk-update-delete"><span>62）EF Core 批量操作（Bulk Update/Delete）</span></a></h3><p><strong>面试官：</strong> EF Core 7 引入的 <code>ExecuteUpdate/ExecuteDelete</code> 为什么比传统方式快？<br><strong>候选人（要点）：</strong> 传统方式需要先查询实体到内存、修改状态、再 SaveChanges（多条 SQL）；新 API 直接生成 <code>UPDATE/DELETE WHERE</code> 语句，零内存加载、单条 SQL 执行。<br><strong>面试官追问：</strong> 这种批量操作会触发实体的 ChangeTracker 和本地拦截器吗？为什么？</p><h3 id="_63-乐观锁与并发令牌" tabindex="-1"><a class="header-anchor" href="#_63-乐观锁与并发令牌"><span>63）乐观锁与并发令牌</span></a></h3><p><strong>面试官：</strong> <code>RowVersion</code> 这种乐观锁机制，除了 update，在 delete 时也能生效吗？为什么？<br><strong>候选人（要点）：</strong> 能生效。<code>DELETE</code> 语句也可以带 <code>WHERE Id = x AND RowVersion = v</code>；如果行版本变了或行没了，受影响行数为 0，抛出并发异常。[3][4]<br><strong>面试官追问：</strong> 并发冲突发生后，你的重试策略是怎样的？无限重试会把数据库打挂吗？</p><h3 id="_64-悲观锁与事务隔离级别" tabindex="-1"><a class="header-anchor" href="#_64-悲观锁与事务隔离级别"><span>64）悲观锁与事务隔离级别</span></a></h3><p><strong>面试官：</strong> 什么时候必须用悲观锁（<code>XLOCK</code> / <code>FOR UPDATE</code>）？EF Core 怎么加悲观锁？<br><strong>候选人（要点）：</strong> 必须强一致且竞争激烈的场景（如秒杀扣库存）；EF Core 原生 API 不支持 Hint，需用 <code>FromSqlRaw(&quot;SELECT ... WITH (UPDLOCK) ...&quot;)</code> 或 <code>BeginTransaction(IsolationLevel.Serializable)</code>。<br><strong>面试官追问：</strong> 高并发下悲观锁会导致死锁吗？怎么避免？</p><h3 id="_65-连接池耗尽-connection-pool-exhaustion" tabindex="-1"><a class="header-anchor" href="#_65-连接池耗尽-connection-pool-exhaustion"><span>65）连接池耗尽（Connection Pool Exhaustion）</span></a></h3><p><strong>面试官：</strong> 生产环境报&quot;连接池超时&quot;，可能的原因有哪些？除了并发大，还有什么？<br><strong>候选人（要点）：</strong> 连接泄漏（未 Dispose）、慢查询（占用连接时间长）、事务未提交/回滚、连接池设置过小。最常见是代码里手动 <code>new SqlConnection</code> 没关。[5]<br><strong>面试官追问：</strong> 怎么用监控指标（如 <a href="http://ADO.NET" target="_blank" rel="noopener noreferrer">ADO.NET</a> Performance Counters）定位是泄漏还是并发不够？</p><h3 id="_66-sql-注入进阶-动态排序" tabindex="-1"><a class="header-anchor" href="#_66-sql-注入进阶-动态排序"><span>66）SQL 注入进阶：动态排序</span></a></h3><p><strong>面试官：</strong> 参数化查询能防 WHERE 注入，那 ORDER BY 动态列名怎么防？<code>OrderBy(input)</code> 安全吗？<br><strong>候选人（要点）：</strong> 参数化不支持列名（只能是值）；<code>OrderBy(input)</code> 如果 input 是用户拼接的 SQL 片段会注入。防御：使用白名单映射（Dictionary&lt;string, string&gt;），或使用強类型 Lambda 表达式构建器。<br><strong>面试官追问：</strong> EF Core 的 <code>FromSqlRaw</code> 如果传入的是 <code>$&quot;{user_input}&quot;</code> 会发生什么？它是参数化还是拼接？</p><h3 id="_67-死锁-deadlock-分析" tabindex="-1"><a class="header-anchor" href="#_67-死锁-deadlock-分析"><span>67）死锁（Deadlock）分析</span></a></h3><p><strong>面试官：</strong> SQL Server 报&quot;死锁&quot;，你怎么读死锁图（Deadlock Graph）？<br><strong>候选人（要点）：</strong> 看资源（Resource）和所有者（Owner）/请求者（Waiter）；A 拿了 X 等 Y，B 拿了 Y 等 X；通常是加锁顺序不一致或索引缺失导致的扫表锁升级。<br><strong>面试官追问：</strong> 怎么用 <code>NOLOCK</code> 或 <code>Snapshot Isolation</code> 缓解死锁？副作用是什么？</p><h3 id="_68-索引失效深度" tabindex="-1"><a class="header-anchor" href="#_68-索引失效深度"><span>68）索引失效深度</span></a></h3><p><strong>面试官：</strong> <code>LIKE &#39;%abc&#39;</code> 为什么不走索引？有什么技术能优化这种左模糊查询？<br><strong>候选人（要点）：</strong> B+ 树是按前缀排序的，左模糊无法利用有序性（只能全扫）；优化可用全文索引（Full-Text Search）、倒排索引（ES）或计算列反转字符串索引。<br><strong>面试官追问：</strong> <code>OR</code> 条件两边都有索引，一定会走索引吗？为什么有时候优化器选择全表扫？</p><h3 id="_69-执行计划-execution-plan" tabindex="-1"><a class="header-anchor" href="#_69-执行计划-execution-plan"><span>69）执行计划（Execution Plan）</span></a></h3><p><strong>面试官：</strong> 怎么看执行计划里的&quot;Key Lookup&quot;（书签查找）？为什么它是性能杀手？<br><strong>候选人（要点）：</strong> Key Lookup 意味着非聚集索引没覆盖所有列，需要回聚集索引取数据（随机 IO）；大量回表导致性能急剧下降。优化方案是使用覆盖索引（Include 列）。<br><strong>面试官追问：</strong> &quot;Index Scan&quot; 和 &quot;Index Seek&quot; 的区别？Scan 一定比 Seek 慢吗？</p><h3 id="_70-复杂查询-group-by-优化" tabindex="-1"><a class="header-anchor" href="#_70-复杂查询-group-by-优化"><span>70）复杂查询：Group By 优化</span></a></h3><p><strong>面试官：</strong> 大数据量 <code>GROUP BY</code> 慢怎么优化？<br><strong>候选人（要点）：</strong> 确保 Group By 字段有索引（消除排序开销）；减少聚合数据量（WHERE 先过滤）；预计算（物化视图/中间表）。<br><strong>面试官追问：</strong> <code>COUNT(DISTINCT col)</code> 在大数据下为什么极慢？有什么近似算法替代（HyperLogLog）？</p><h3 id="_71-临时表-vs-表变量-vs-cte" tabindex="-1"><a class="header-anchor" href="#_71-临时表-vs-表变量-vs-cte"><span>71）临时表 vs 表变量 vs CTE</span></a></h3><p><strong>面试官：</strong> 存储过程里用临时表（#Temp）还是表变量（@Table）？CTE（公用表表达式）是临时的吗？<br><strong>候选人（要点）：</strong> 临时表支持索引/统计信息，适合大数据量；表变量在内存（也可能落盘），无统计信息，适合小数据。CTE 是语法糖（视图），不存储数据（除非递归 CTE 可能溢出）。<br><strong>面试官追问：</strong> 递归 CTE 怎么写？如果不加最大递归深度限制会怎样？</p><h3 id="_72-tvp-表值参数" tabindex="-1"><a class="header-anchor" href="#_72-tvp-表值参数"><span>72）TVP（表值参数）</span></a></h3><p><strong>面试官：</strong> 怎么一次性插入 1 万条明细数据？循环 Insert 还是别的？<br><strong>候选人（要点）：</strong> 循环 Insert 最慢（网络开销大）；可用 <code>SqlBulkCopy</code>（最快）或 TVP（表值参数）传给存储过程；EF Core 的 <code>AddRange</code> + <code>SaveChanges</code> 也会自动批处理（Batching）。<br><strong>面试官追问：</strong> <code>SqlBulkCopy</code> 的事务怎么控制？</p><h3 id="_73-分库分表策略" tabindex="-1"><a class="header-anchor" href="#_73-分库分表策略"><span>73）分库分表策略</span></a></h3><p><strong>面试官：</strong> 垂直拆分和水平拆分的区别？水平拆分（Sharding）后的分页查询怎么做？<br><strong>候选人（要点）：</strong> 垂直按业务模块拆（列/表），水平按数据量拆（行）。水平分表后的全局分页最难：只能&quot;全局查再排序截取&quot;（性能差）或&quot;禁止跳页&quot;（只提供下一页，按 ID 游标）。<br><strong>面试官追问：</strong> 分库后的分布式事务（跨库转账）怎么解？（TCC / 消息最终一致性）。</p><h3 id="_74-数据库游标-cursor" tabindex="-1"><a class="header-anchor" href="#_74-数据库游标-cursor"><span>74）数据库游标（Cursor）</span></a></h3><p><strong>面试官：</strong> 为什么 DBA 都不让用游标？集合操作 vs 逐行操作？<br><strong>候选人（要点）：</strong> 游标是逐行处理，无法利用集合算法优化，持有锁时间长，性能极差。应尽量用 Set-based SQL（UPDATE ... FROM ...）。<br><strong>面试官追问：</strong> 必须逐行处理的场景（如复杂的跨行状态依赖计算）怎么优化？（Window Function / 递归 CTE）。</p><h3 id="_75-window-function-窗口函数" tabindex="-1"><a class="header-anchor" href="#_75-window-function-窗口函数"><span>75）Window Function（窗口函数）</span></a></h3><p><strong>面试官：</strong> <code>ROW_NUMBER()</code>、<code>RANK()</code>、<code>DENSE_RANK()</code> 区别？给一个&quot;分组取最新一条&quot;的 SQL。<br><strong>候选人（要点）：</strong> <code>ROW_NUMBER</code> 连续唯一（1,2,3），<code>RANK</code> 并列跳号（1,1,3），<code>DENSE_RANK</code> 并列不跳号（1,1,2）。分组取最新：<code>PARTITION BY GroupId ORDER BY Time DESC</code> 取 RowNum=1。<br><strong>面试官追问：</strong> 窗口函数是在 WHERE 之前还是之后执行？能放在 WHERE 里吗？</p><h3 id="_76-json-数据存储" tabindex="-1"><a class="header-anchor" href="#_76-json-数据存储"><span>76）JSON 数据存储</span></a></h3><p><strong>面试官：</strong> SQL Server / MySQL 的 JSON 类型好用吗？和 MongoDB 怎么选？<br><strong>候选人（要点）：</strong> 关系型数据库存 JSON 适合&quot;大部分结构化 + 少量扩展字段&quot;；如果全是 JSON 且读写高频、Schema 极不稳定，MongoDB 更优。<br><strong>面试官追问：</strong> 在 JSON 字段上怎么建索引？性能如何？</p><h3 id="_77-cdc-change-data-capture" tabindex="-1"><a class="header-anchor" href="#_77-cdc-change-data-capture"><span>77）CDC（Change Data Capture）</span></a></h3><p><strong>面试官：</strong> 怎么实时同步数据库变更到 ES/Redis？触发器行吗？<br><strong>候选人（要点）：</strong> 触发器性能差且耦合。CDC（如 Debezium / Canal）读取数据库事务日志（Binlog / LSN），异步推送到 MQ，性能影响小且可靠。<br><strong>面试官追问：</strong> 软删除的数据 CDC 能捕获到吗？全量同步 + 增量同步怎么配合？</p><h3 id="_78-数据库备份与恢复模型" tabindex="-1"><a class="header-anchor" href="#_78-数据库备份与恢复模型"><span>78）数据库备份与恢复模型</span></a></h3><p><strong>面试官：</strong> 完整恢复模式（Full Recovery）和简单模式（Simple）的区别？事务日志为什么会撑爆磁盘？<br><strong>候选人（要点）：</strong> 完整模式记录所有日志，支持点对点恢复（PITR），日志需要手动备份截断，否则无限增长；简单模式自动截断日志，只能恢复到全备点。<br><strong>面试官追问：</strong> &quot;尾日志备份&quot;（Tail-Log Backup）是什么？灾难恢复时的最后一步？</p><h3 id="_79-ef-core-拦截器-interceptor" tabindex="-1"><a class="header-anchor" href="#_79-ef-core-拦截器-interceptor"><span>79）EF Core 拦截器（Interceptor）</span></a></h3><p><strong>面试官：</strong> 怎么在 SQL 执行前后做埋点（如慢 SQL 日志、动态改表名）？<br><strong>候选人（要点）：</strong> 继承 <code>DbCommandInterceptor</code>，重写 <code>ReaderExecuting</code> 等方法。可修改 CommandText 实现分表逻辑，或记录耗时。<br><strong>面试官追问：</strong> 在拦截器里能修改 Result 吗？怎么实现二级缓存（查询拦截）？</p><h3 id="_80-compiled-query-编译查询" tabindex="-1"><a class="header-anchor" href="#_80-compiled-query-编译查询"><span>80）Compiled Query（编译查询）</span></a></h3><p><strong>面试官：</strong> <code>EF.CompileQuery</code> 是什么？为什么能提升性能？<br><strong>候选人（要点）：</strong> 预编译 LINQ 表达式树为委托，避免每次查询都重新解析表达式树的开销；适合高频执行的简单查询。<br><strong>面试官追问：</strong> 编译查询支持异步吗？有什么限制？</p><h3 id="_81-shadow-property-实战" tabindex="-1"><a class="header-anchor" href="#_81-shadow-property-实战"><span>81）Shadow Property 实战</span></a></h3><p><strong>面试官：</strong> 怎么用影子属性实现通用的&quot;最后修改人/时间&quot;记录？<br><strong>候选人（要点）：</strong> 在 <code>OnModelCreating</code> 里统一为所有实体注册 Shadow Property；在 <code>SaveChanges</code> 拦截器里自动赋值。<br><strong>面试官追问：</strong> 查询时怎么拿到影子属性的值？（<code>EF.Property&lt;T&gt;(blog, &quot;Created&quot;)</code>）。</p><h3 id="_82-value-conversion-值转换" tabindex="-1"><a class="header-anchor" href="#_82-value-conversion-值转换"><span>82）Value Conversion（值转换）</span></a></h3><p><strong>面试官：</strong> 怎么把数据库里的 int 映射成代码里的 Enum？或者把 JSON 字符串映射成对象？<br><strong>候选人（要点）：</strong> 使用 <code>HasConversion</code>；定义转换器（Provider &lt;-&gt; Model）。适合处理枚举、加密字段、JSON 对象。<br><strong>面试官追问：</strong> 值转换后的字段能做 LINQ 查询条件吗？翻译成的 SQL 效率如何？</p><h3 id="_83-owned-entity-type-从属实体" tabindex="-1"><a class="header-anchor" href="#_83-owned-entity-type-从属实体"><span>83）Owned Entity Type（从属实体）</span></a></h3><p><strong>面试官：</strong> <code>OwnsOne</code> 是什么？和普通导航属性区别？<br><strong>候选人（要点）：</strong> 从属实体没有独立 ID，数据通常内嵌在主表（多列）或共享主键；适合值对象（Value Object），如 Address (City, Street)。<br><strong>面试官追问：</strong> <code>OwnsMany</code>（集合）怎么存储？（通常是独立表）。</p><h3 id="_84-global-query-filter-进阶" tabindex="-1"><a class="header-anchor" href="#_84-global-query-filter-进阶"><span>84）Global Query Filter 进阶</span></a></h3><p><strong>面试官：</strong> 全局过滤器（软删除）会影响 <code>IgnoreQueryFilters()</code> 后的性能吗？<br><strong>候选人（要点）：</strong> 过滤器本质是追加 WHERE 条件；加上索引（如 IsDeleted）则不影响，没索引可能全表扫。<code>IgnoreQueryFilters</code> 移除 WHERE，可能利用不同的索引。<br><strong>面试官追问：</strong> 多租户过滤器在关联查询（Include）时生效吗？（生效，自动追加到 JOIN 条件）。</p><h3 id="_85-dbcontext-pooling" tabindex="-1"><a class="header-anchor" href="#_85-dbcontext-pooling"><span>85）DbContext Pooling</span></a></h3><p><strong>面试官：</strong> <code>AddDbContextPool</code> 为什么能提升性能？有什么坑？<br><strong>候选人（要点）：</strong> 复用 Context 实例，减少创建/销毁开销；坑在于 Context 必须是无状态的（除了 DbConnection），如果注入了有状态的 Scoped 服务且没重置，会发生状态污染。<br><strong>面试官追问：</strong> 怎么正确重置 Context 状态？</p><h3 id="_86-ef-core-8-primitive-collections" tabindex="-1"><a class="header-anchor" href="#_86-ef-core-8-primitive-collections"><span>86）EF Core 8 Primitive Collections</span></a></h3><p><strong>面试官：</strong> EF Core 8 支持 <code>List&lt;int&gt;</code> 直接存库了吗？底层是怎么存的？<br><strong>候选人（要点）：</strong> 支持；底层通常存为 JSON 数组（SQL Server / PG）或特定分隔字符串，查询时支持 <code>Contains</code> 翻译。<br><strong>面试官追问：</strong> 这种 JSON 数组查询性能如何？能走索引吗？</p><h3 id="_87-hierarchyid-与树形结构" tabindex="-1"><a class="header-anchor" href="#_87-hierarchyid-与树形结构"><span>87）HierarchyId 与树形结构</span></a></h3><p><strong>面试官：</strong> 怎么存储树形结构（如部门树）？递归查询怎么优化？<br><strong>候选人（要点）：</strong> 邻接表（ParentId）查询慢（递归）；SQL Server <code>HierarchyId</code> 类型存储路径，支持高效的子树查询/层级判断；或用闭包表/路径枚举法。<br><strong>面试官追问：</strong> 删除中间节点时，子节点怎么处理？</p><h3 id="_88-spatial-data-空间数据" tabindex="-1"><a class="header-anchor" href="#_88-spatial-data-空间数据"><span>88）Spatial Data（空间数据）</span></a></h3><p><strong>面试官：</strong> 怎么存经纬度并查&quot;附近 5 公里的人&quot;？<br><strong>候选人（要点）：</strong> 使用 <code>NetTopologySuite</code> 库，数据库用 <code>Geography</code> 类型（SQL Server / PostGIS）；利用空间索引做 ST_Distance 查询。<br><strong>面试官追问：</strong> 简单的矩形范围查询 vs 真实的地理距离计算？</p><h3 id="_89-in-memory-database-坑" tabindex="-1"><a class="header-anchor" href="#_89-in-memory-database-坑"><span>89）In-Memory Database 坑</span></a></h3><p><strong>面试官：</strong> 单元测试推荐用 EF Core In-Memory 吗？为什么有人反对？<br><strong>候选人（要点）：</strong> 不推荐。In-Memory 行为与真实 DB 差异大（不支持事务隔离、约束检查弱、LINQ 翻译不同）；推荐用 Testcontainers 跑真实数据库容器。<br><strong>面试官追问：</strong> SQLite In-Memory 模式怎么样？（比纯内存库好，但仍有 SQL 语法差异）。</p><h3 id="_90-raw-sql-与-dapper-混用" tabindex="-1"><a class="header-anchor" href="#_90-raw-sql-与-dapper-混用"><span>90）Raw SQL 与 Dapper 混用</span></a></h3><p><strong>面试官：</strong> EF Core 项目里什么时候需要引入 Dapper？怎么共享事务？<br><strong>候选人（要点）：</strong> 复杂报表/极致性能查询用 Dapper；共享事务需从 <code>DbContext.Database.GetDbConnection()</code> 获取连接，并使用 <code>DbContext.Database.CurrentTransaction.GetDbTransaction()</code> 传递事务对象。<br><strong>面试官追问：</strong> Dapper 的查询结果怎么做 Change Tracking？（不能，是只读的）。</p><h2 id="🟡-中级梯队-设计模式进阶与架构模式-91–120-1" tabindex="-1"><a class="header-anchor" href="#🟡-中级梯队-设计模式进阶与架构模式-91–120-1"><span>🟡 中级梯队：设计模式进阶与架构模式（91–120）[1]</span></a></h2><h3 id="_91-单例模式的线程安全与破坏" tabindex="-1"><a class="header-anchor" href="#_91-单例模式的线程安全与破坏"><span>91）单例模式的线程安全与破坏</span></a></h3><p><strong>面试官：</strong> 饿汉式、懒汉式、双重检查锁（DCL）的区别？DCL 为什么要判两次空？<br><strong>候选人（要点）：</strong> 饿汉类加载即创建（安全但可能浪费）；懒汉延迟加载（需加锁）；DCL 第一次判空避锁（性能），第二次判空保单例（安全）。<br><strong>面试官追问：</strong> 反射和序列化能破坏单例吗？怎么防止？（枚举单例 / readResolve）。</p><h3 id="_92-简单工厂-vs-工厂方法-vs-抽象工厂" tabindex="-1"><a class="header-anchor" href="#_92-简单工厂-vs-工厂方法-vs-抽象工厂"><span>92）简单工厂 vs 工厂方法 vs 抽象工厂</span></a></h3><p><strong>面试官：</strong> 什么时候该升级到工厂方法？抽象工厂到底是解决什么问题的？<br><strong>候选人（要点）：</strong> 简单工厂违背 OCP（加新类改 switch）；工厂方法符合 OCP（每类一工厂）；抽象工厂解决&quot;产品族&quot;（如 Windows 按钮+文本框 vs Mac 按钮+文本框）的一致性创建。<br><strong>面试官追问：</strong> .NET Core DI 容器里的 <code>AddTransient&lt;IFoo, Foo&gt;()</code> 本质是哪种工厂模式？</p><h3 id="_93-代理模式-vs-装饰器模式" tabindex="-1"><a class="header-anchor" href="#_93-代理模式-vs-装饰器模式"><span>93）代理模式 vs 装饰器模式</span></a></h3><p><strong>面试官：</strong> 结构都是&quot;持有一个对象并实现相同接口&quot;，区别在哪？<br><strong>候选人（要点）：</strong> 意图不同。代理（Proxy）控制访问（权限、延迟加载、远程调用）；装饰器（Decorator）增强功能（日志、缓存、加密）。<br><strong>面试官追问：</strong> 动态代理（Dynamic Proxy）是什么？AOP（如 Castle DynamicProxy）是怎么实现的？</p><h3 id="_94-适配器模式-adapter-实战" tabindex="-1"><a class="header-anchor" href="#_94-适配器模式-adapter-实战"><span>94）适配器模式（Adapter）实战</span></a></h3><p><strong>面试官：</strong> 你的系统要接一个新的第三方支付，接口和现在的完全不一样，怎么用适配器？<br><strong>候选人（要点）：</strong> 定义统一目标接口 <code>IPayment</code>；创建 <code>AliPayAdapter</code> 实现该接口，内部持有 <code>AliPaySdk</code> 并转换调用逻辑。<br><strong>面试官追问：</strong> 类适配器（继承）和对象适配器（组合）选哪个？（优先组合，支持多继承/灵活性）。</p><h3 id="_95-观察者模式-vs-发布订阅" tabindex="-1"><a class="header-anchor" href="#_95-观察者模式-vs-发布订阅"><span>95）观察者模式 vs 发布订阅</span></a></h3><p><strong>面试官：</strong> 观察者模式和发布-订阅模式（Pub/Sub）是一回事吗？<br><strong>候选人（要点）：</strong> 不完全一样。观察者通常是直接耦合（Subject 持有 Observer 列表）；Pub/Sub 通常有中间 Broker（如 EventBus/MQ），发布者不认识订阅者。<br><strong>面试官追问：</strong> 在 C# 中实现弱引用观察者（Weak Event Pattern）是为了解决什么问题？</p><h3 id="_96-策略模式与工厂结合" tabindex="-1"><a class="header-anchor" href="#_96-策略模式与工厂结合"><span>96）策略模式与工厂结合</span></a></h3><p><strong>面试官：</strong> 只有策略模式，客户端还是要 <code>new StrategyA()</code>，怎么消除这个依赖？<br><strong>候选人（要点）：</strong> 结合工厂模式或 DI。创建一个 <code>StrategyFactory</code>，根据上下文（如 UserType）返回对应的 <code>IStrategy</code> 实例；或利用 DI 的 <code>IEnumerable&lt;IStrategy&gt;</code> 注入并按 Key 查找。<br><strong>面试官追问：</strong> 如果策略很多，怎么避免工厂里的 <code>switch-case</code> 爆炸？（使用字典映射 / 反射扫描）。</p><h3 id="_97-模板方法模式-template-method" tabindex="-1"><a class="header-anchor" href="#_97-模板方法模式-template-method"><span>97）模板方法模式（Template Method）</span></a></h3><p><strong>面试官：</strong> <a href="http://ASP.NET" target="_blank" rel="noopener noreferrer">ASP.NET</a> Core 的生命周期里哪里体现了模板方法？<br><strong>候选人（要点）：</strong> <code>Controller</code> 基类的 <code>OnActionExecuting</code>、<code>OnActionExecuted</code> 等虚方法提供了钩子；框架定义了执行流程骨架，子类重写特定步骤。<br><strong>面试官追问：</strong> 模板方法和回调函数（Callback）相比，优缺点是什么？</p><h3 id="_98-责任链模式-chain-of-responsibility" tabindex="-1"><a class="header-anchor" href="#_98-责任链模式-chain-of-responsibility"><span>98）责任链模式（Chain of Responsibility）</span></a></h3><p><strong>面试官：</strong> 中间件管道是责任链，那业务代码里什么时候用？<br><strong>候选人（要点）：</strong> 复杂审批流（主管 -&gt; 经理 -&gt; 总监）、多级校验规则。链条上的每个节点决定是否处理或传给下家。<br><strong>面试官追问：</strong> 纯责任链（只处理或传）和不纯责任链（处理一部分再传）的区别？</p><h3 id="_99-建造者模式-builder" tabindex="-1"><a class="header-anchor" href="#_99-建造者模式-builder"><span>99）建造者模式（Builder）</span></a></h3><p><strong>面试官：</strong> <code>StringBuilder</code> 是建造者模式吗？Fluent API（如 EF Core 配置）呢？<br><strong>候选人（要点）：</strong> 是变体。传统 Builder 分离&quot;构建过程&quot;与&quot;表示&quot;；Fluent API 侧重于链式调用构建复杂对象配置，提升可读性。<br><strong>面试官追问：</strong> 什么时候用 Builder 而不是长参数构造函数？（参数多、组合灵活、需校验构建步骤）。</p><h3 id="_100-原型模式-prototype-与深拷贝" tabindex="-1"><a class="header-anchor" href="#_100-原型模式-prototype-与深拷贝"><span>100）原型模式（Prototype）与深拷贝</span></a></h3><p><strong>面试官：</strong> <code>ICloneable</code> 为什么不推荐用？怎么实现深拷贝？<br><strong>候选人（要点）：</strong> <code>Clone</code> 语义模糊（深拷贝还是浅拷贝？）。深拷贝推荐序列化（JSON/Binary）或手动递归复制；浅拷贝用 <code>MemberwiseClone</code>。<br><strong>面试官追问：</strong> 序列化做深拷贝的性能损耗怎么解决？（使用表达式树/Emit 生成拷贝代码）。</p><h3 id="_101-享元模式-flyweight" tabindex="-1"><a class="header-anchor" href="#_101-享元模式-flyweight"><span>101）享元模式（Flyweight）</span></a></h3><p><strong>面试官：</strong> 字符串驻留池是享元模式吗？还有什么场景用享元？<br><strong>候选人（要点）：</strong> 是。场景：大量细粒度对象的复用（如围棋棋子、游戏里的树木模型），提取内部状态（共享）与外部状态（传入）。<br><strong>面试官追问：</strong> 享元模式如何解决线程安全问题？（内部状态必须不可变）。</p><h3 id="_102-组合模式-composite" tabindex="-1"><a class="header-anchor" href="#_102-组合模式-composite"><span>102）组合模式（Composite）</span></a></h3><p><strong>面试官：</strong> 怎么处理树形结构（如菜单、部门）的统一操作？<br><strong>候选人（要点）：</strong> 让&quot;叶子节点&quot;和&quot;组合节点&quot;实现相同接口（<code>Component</code>），组合节点持有 <code>List&lt;Component&gt;</code>；客户端可以一致对待单个对象和组合对象。<br><strong>面试官追问：</strong> 透明性（接口有 Add/Remove）vs 安全性（只在组合节点有 Add/Remove）的权衡？</p><h3 id="_103-命令模式-command" tabindex="-1"><a class="header-anchor" href="#_103-命令模式-command"><span>103）命令模式（Command）</span></a></h3><p><strong>面试官：</strong> 为什么要封装&quot;命令&quot;对象？直接调用方法不行吗？<br><strong>候选人（要点）：</strong> 解耦请求者与接收者；支持撤销/重做（Undo/Redo）、宏命令（组合）、队列化执行（如任务队列）。<br><strong>面试官追问：</strong> CQRS 里的 Command 是命令模式吗？（是，承载意图的数据对象）。</p><h3 id="_104-状态模式-state" tabindex="-1"><a class="header-anchor" href="#_104-状态模式-state"><span>104）状态模式（State）</span></a></h3><p><strong>面试官：</strong> 订单状态流转（待支付 -&gt; 待发货 -&gt; 已完成）怎么消除大量 <code>if-else</code>？<br><strong>候选人（要点）：</strong> 将每种状态封装成类，实现统一接口 <code>Handle()</code>；Context 持有当前状态，委托给状态对象处理行为并切换状态。<br><strong>面试官追问：</strong> 状态模式和策略模式结构很像，区别在哪？（状态模式内部控制状态流转，客户端不关心；策略模式由客户端指定策略）。</p><h3 id="_105-中介者模式-mediator" tabindex="-1"><a class="header-anchor" href="#_105-中介者模式-mediator"><span>105）中介者模式（Mediator）</span></a></h3><p><strong>面试官：</strong> MediatR 库用过吗？它属于什么模式？解决了什么问题？<br><strong>候选人（要点）：</strong> 中介者模式。解决对象间网状依赖（紧耦合），改为星状依赖（只依赖中介者）；实现进程内消息解耦（CQRS Handler）。<br><strong>面试官追问：</strong> 中介者会不会变成&quot;上帝对象&quot;（God Object）？怎么避免？</p><h3 id="_106-迭代器模式-iterator-与-yield" tabindex="-1"><a class="header-anchor" href="#_106-迭代器模式-iterator-与-yield"><span>106）迭代器模式（Iterator）与 yield</span></a></h3><p><strong>面试官：</strong> <code>foreach</code> 怎么工作的？<code>yield return</code> 编译成了什么？<br><strong>候选人（要点）：</strong> 依赖 <code>IEnumerable</code> / <code>IEnumerator</code>；<code>yield</code> 编译成状态机类，按需生成序列元素（延迟执行）。<br><strong>面试官追问：</strong> 在 <code>yield</code> 方法里写 <code>try-catch</code> 和 <code>try-finally</code> 有什么限制？</p><h3 id="_107-备忘录模式-memento" tabindex="-1"><a class="header-anchor" href="#_107-备忘录模式-memento"><span>107）备忘录模式（Memento）</span></a></h3><p><strong>面试官：</strong> 怎么实现&quot;保存草稿&quot;或&quot;回滚配置&quot;功能？<br><strong>候选人（要点）：</strong> 捕获对象内部状态并存到外部（Memento），且不破坏封装（只有原发器能读 Memento 内容）。<br><strong>面试官追问：</strong> 状态量大时怎么优化内存？（增量存储 / 序列化存储）。</p><h3 id="_108-访问者模式-visitor" tabindex="-1"><a class="header-anchor" href="#_108-访问者模式-visitor"><span>108）访问者模式（Visitor）</span></a></h3><p><strong>面试官：</strong> 表达式树遍历（ExpressionVisitor）是怎么实现的？<br><strong>候选人（要点）：</strong> 数据结构（AST节点）稳定，操作（打印、编译、分析）多变；利用双分派（<code>Accept(Visitor)</code> -&gt; <code>Visitor.Visit(this)</code>）在不改节点类的情况下扩展操作。<br><strong>面试官追问：</strong> 为什么说访问者模式破坏了封装？（Visitor 需要访问节点内部细节）。</p><h3 id="_109-桥接模式-bridge" tabindex="-1"><a class="header-anchor" href="#_109-桥接模式-bridge"><span>109）桥接模式（Bridge）</span></a></h3><p><strong>面试官：</strong> 什么时候用桥接而不是继承？<br><strong>候选人（要点）：</strong> 当一个类有多个维度的变化（如&quot;形状&quot;和&quot;颜色&quot;），继承会导致类爆炸（M*N）；桥接通过组合将抽象部分与实现部分分离，独立变化。<br><strong>面试官追问：</strong> JDBC / <a href="http://ADO.NET" target="_blank" rel="noopener noreferrer">ADO.NET</a> 驱动程序管理是桥接模式吗？</p><h3 id="_110-解释器模式-interpreter" tabindex="-1"><a class="header-anchor" href="#_110-解释器模式-interpreter"><span>110）解释器模式（Interpreter）</span></a></h3><p><strong>面试官：</strong> 你做过简单的规则引擎吗？比如解析 &quot;A &gt; 10 AND B &lt; 5&quot;。<br><strong>候选人（要点）：</strong> 定义文法规则的类（AndExpression, GreaterExpression），构建语法树并解释执行。<br><strong>面试官追问：</strong> 性能要求高时为什么不用解释器模式？（慢，推荐编译成 Expression Tree 或 IL）。</p><h3 id="_111-贫血模型-vs-充血模型-ddd-基础" tabindex="-1"><a class="header-anchor" href="#_111-贫血模型-vs-充血模型-ddd-基础"><span>111）贫血模型 vs 充血模型（DDD 基础）</span></a></h3><p><strong>面试官：</strong> 为什么说只有 getter/setter 的实体是&quot;贫血&quot;的？充血模型长什么样？<br><strong>候选人（要点）：</strong> 贫血只有数据，逻辑散落在 Service，破坏封装；充血把业务逻辑（验证、状态变更）内聚在实体中，Service 只做编排。<br><strong>面试官追问：</strong> EF Core 怎么支持充血模型？（私有字段映射、构造函数注入、只读属性）。</p><h3 id="_112-实体-vs-值对象-value-object" tabindex="-1"><a class="header-anchor" href="#_112-实体-vs-值对象-value-object"><span>112）实体 vs 值对象（Value Object）</span></a></h3><p><strong>面试官：</strong> DDD 里实体和值对象的本质区别？值对象为什么是不可变的？<br><strong>候选人（要点）：</strong> 实体有唯一标识（ID），生命周期连续；值对象由属性定义身份（属性一样就是同一个），无 ID，不可变以保证副作用可控。<br><strong>面试官追问：</strong> EF Core 怎么映射值对象？（<code>OwnsOne</code> / Complex Type）。</p><h3 id="_113-聚合根-aggregate-root-设计" tabindex="-1"><a class="header-anchor" href="#_113-聚合根-aggregate-root-设计"><span>113）聚合根（Aggregate Root）设计</span></a></h3><p><strong>面试官：</strong> 聚合根的职责是什么？为什么不能直接修改聚合内部的实体？<br><strong>候选人（要点）：</strong> 维护一致性边界（事务边界）。外部只能通过聚合根操作内部，防止破坏业务规则（如&quot;订单明细总额必须等于订单总额&quot;）。<br><strong>面试官追问：</strong> 一个事务能修改多个聚合吗？（原则上不能，应通过最终一致性/事件驱动）。</p><h3 id="_114-仓储模式-repository" tabindex="-1"><a class="header-anchor" href="#_114-仓储模式-repository"><span>114）仓储模式（Repository）</span></a></h3><p><strong>面试官：</strong> EF Core 的 <code>DbSet</code> 已经是仓储了，为什么还要再包一层 Repository？<br><strong>候选人（要点）：</strong> 解耦特定 ORM，提供领域语义的方法（<code>FindActiveUsers</code> 而不是 <code>Where(x=&gt;...)</code>），便于 Mock 测试。但对于简单 CRUD，直接用 DbContext 也是可接受的（Pragmatic DDD）。<br><strong>面试官追问：</strong> <code>IQueryable</code> 能从 Repository 泄露出去吗？（不建议，泄露了数据库实现细节）。</p><h3 id="_115-工作单元-unit-of-work" tabindex="-1"><a class="header-anchor" href="#_115-工作单元-unit-of-work"><span>115）工作单元（Unit of Work）</span></a></h3><p><strong>面试官：</strong> UoW 解决了什么问题？它和 Repository 怎么配合？<br><strong>候选人（要点）：</strong> 管理事务，确保多个 Repository 的操作在一次提交中原子完成。通常 DbContext 本身就是 UoW 实现。<br><strong>面试官追问：</strong> 跨库/跨服务的 UoW 怎么做？（分布式事务 / TCC）。</p><h3 id="_116-领域事件-domain-event" tabindex="-1"><a class="header-anchor" href="#_116-领域事件-domain-event"><span>116）领域事件（Domain Event）</span></a></h3><p><strong>面试官：</strong> 领域事件和普通消息队列的区别？什么时候触发？<br><strong>候选人（要点）：</strong> 领域事件是业务发生的客观事实（&quot;UserRegistered&quot;），用于解耦聚合间逻辑。触发时机：通常在事务提交前（进程内副作用）或提交后（发 MQ）。<br><strong>面试官追问：</strong> 怎么保证事件发送与数据库提交的原子性？（Outbox 模式）。</p><h3 id="_117-领域服务-domain-service" tabindex="-1"><a class="header-anchor" href="#_117-领域服务-domain-service"><span>117）领域服务（Domain Service）</span></a></h3><p><strong>面试官：</strong> 什么时候需要领域服务？和应用服务（Application Service）的区别？<br><strong>候选人（要点）：</strong> 当逻辑涉及多个聚合且无法归属于任一聚合时（如&quot;转账&quot;）。应用服务负责编排（加载、调域服务、保存、发邮件），不含核心业务规则；领域服务含核心规则。<br><strong>面试官追问：</strong> 领域服务可以调仓储吗？（可以，但尽量只依赖抽象）。</p><h3 id="_118-cqrs-命令查询职责分离" tabindex="-1"><a class="header-anchor" href="#_118-cqrs-命令查询职责分离"><span>118）CQRS（命令查询职责分离）</span></a></h3><p><strong>面试官：</strong> 为什么要读写分离模型？CQRS 一定要双数据库吗？<br><strong>候选人（要点）：</strong> 读写需求不同（写重一致性，读重查询灵活性）。不一定双库，可以单库 + 读写模型分离（写实体，读 DTO）；进阶才是双库（同步/异步）。<br><strong>面试官追问：</strong> 异步 CQRS 的数据延迟（最终一致性）怎么处理用户体验？（前端乐观更新 / 轮询）。</p><h3 id="_119-六边形架构-洋葱架构" tabindex="-1"><a class="header-anchor" href="#_119-六边形架构-洋葱架构"><span>119）六边形架构 / 洋葱架构</span></a></h3><p><strong>面试官：</strong> 核心思想是什么？依赖方向是怎样的？<br><strong>候选人（要点）：</strong> 依赖反转：外层（UI/DB）依赖内层（Domain），核心业务逻辑不依赖任何基础设施。通过端口（Port）和适配器（Adapter）交互。<br><strong>面试官追问：</strong> Clean Architecture（整洁架构）和它们的区别？（本质一样，分层命名不同）。</p><h3 id="_120-微服务拆分原则" tabindex="-1"><a class="header-anchor" href="#_120-微服务拆分原则"><span>120）微服务拆分原则</span></a></h3><p><strong>面试官：</strong> 什么时候不该拆微服务？拆分过细有什么后果？<br><strong>候选人（要点）：</strong> 业务不清晰、团队小、基础设施弱时不拆。后果：分布式事务噩梦、延迟增加、运维复杂度爆炸、排障困难。<br><strong>面试官追问：</strong> &quot;按技术拆&quot;（如日志服务、鉴权服务）好还是&quot;按业务拆&quot;（订单、库存）好？（优先按业务领域拆）。</p><h2 id="🟡-中级梯队-redis-高级特性与分布式锁深度-121–150-1" tabindex="-1"><a class="header-anchor" href="#🟡-中级梯队-redis-高级特性与分布式锁深度-121–150-1"><span>🟡 中级梯队：Redis 高级特性与分布式锁深度（121–150）[1]</span></a></h2><h3 id="_121-redis-线程模型深度" tabindex="-1"><a class="header-anchor" href="#_121-redis-线程模型深度"><span>121）Redis 线程模型深度</span></a></h3><p><strong>面试官：</strong> 为什么 Redis 6.0 引入了多线程？这是否违背了&quot;单线程&quot;设计？<br><strong>候选人（要点）：</strong> 核心命令执行仍是单线程（保证无锁、简单）；多线程仅用于网络 IO（读写 Socket 缓冲区）和协议解析，解决网络带宽瓶颈。<br><strong>面试官追问：</strong> 如果你的 Redis CPU 飙升，但 QPS 不高，可能是什么原因？（O(N) 慢查询、大 Key 序列化）。</p><h3 id="_122-bitmap-与-hyperloglog" tabindex="-1"><a class="header-anchor" href="#_122-bitmap-与-hyperloglog"><span>122）Bitmap 与 HyperLogLog</span></a></h3><p><strong>面试官：</strong> 怎么在 Redis 里统计&quot;亿级日活用户&quot;（UV）？内存占用怎么估算？<br><strong>候选人（要点）：</strong></p><ol><li><strong>Bitmap</strong>：适合连续 ID，精确，1 亿用户约 12MB。</li><li><strong>HyperLogLog</strong>：适合非数字 ID 或巨量数据，允许误差（0.81%），固定 12KB。<br><strong>面试官追问：</strong> 怎么统计&quot;连续 7 天登录的用户&quot;？（Bitmap 做位运算 <code>BITOP AND</code>）。</li></ol><h3 id="_123-geohash-原理与应用" tabindex="-1"><a class="header-anchor" href="#_123-geohash-原理与应用"><span>123）GeoHash 原理与应用</span></a></h3><p><strong>面试官：</strong> <code>GEOADD</code> 底层存的是什么结构？怎么实现&quot;附近的人&quot;？<br><strong>候选人（要点）：</strong> 底层是 ZSet。经纬度经过 GeoHash 算法转为 52 位整数（score），利用 ZSet 的范围查询（RangeByScore）查找相邻区域点。<br><strong>面试官追问：</strong> 边界问题（在格子边缘）怎么解决？（同时查询周围 8 个格子）。</p><h3 id="_124-bloom-filter-布隆过滤器-插件" tabindex="-1"><a class="header-anchor" href="#_124-bloom-filter-布隆过滤器-插件"><span>124）Bloom Filter（布隆过滤器）插件</span></a></h3><p><strong>面试官：</strong> RedisModule（如 RedisBloom）比自己写 BitMap 实现布隆过滤器好在哪？<br><strong>候选人（要点）：</strong> 性能更高（C实现）、支持动态扩容（Scalable Bloom Filter）、API 封装更好（<code>BF.ADD</code> / <code>BF.EXISTS</code>）。<br><strong>面试官追问：</strong> 布隆过滤器能删除元素吗？为什么？（传统的不行，Counting Bloom Filter 可以但耗内存）。</p><h3 id="_125-stream-消息队列" tabindex="-1"><a class="header-anchor" href="#_125-stream-消息队列"><span>125）Stream（消息队列）</span></a></h3><p><strong>面试官：</strong> Redis 5.0 的 Stream 和 List/PubSub 做队列的区别？<br><strong>候选人（要点）：</strong></p><ul><li>List：无法多播，ACK 麻烦。</li><li>PubSub：消息不持久化，发后即焚。</li><li>Stream：支持持久化、消费者组（Consumer Group）、ACK、消息回溯，类似 Kafka 轻量版。<br><strong>面试官追问：</strong> Stream 消息堆积会撑爆内存吗？怎么限制长度？（<code>XADD ... MAXLEN ~ 1000</code>）。</li></ul><h3 id="_126-lua-脚本的原子性与限制" tabindex="-1"><a class="header-anchor" href="#_126-lua-脚本的原子性与限制"><span>126）Lua 脚本的原子性与限制</span></a></h3><p><strong>面试官：</strong> Lua 脚本能保证原子性，那它是事务吗？脚本里能写死循环吗？<br><strong>候选人（要点）：</strong> 保证原子性（脚本执行期间不执行其他命令）。不是 ACID 事务（中途报错不回滚）。默认有超时时间（5s），死循环会阻塞 Redis 导致不可用。<br><strong>面试官追问：</strong> <code>SCRIPT LOAD</code> 和 <code>EVALSHA</code> 是为了解决什么问题？（减少网络带宽，缓存脚本）。</p><h3 id="_127-keys-淘汰策略深度" tabindex="-1"><a class="header-anchor" href="#_127-keys-淘汰策略深度"><span>127）Keys 淘汰策略深度</span></a></h3><p><strong>面试官：</strong> <code>allkeys-lru</code> 和 <code>volatile-lru</code> 选哪个？LRU 算法是标准的吗？<br><strong>候选人（要点）：</strong> 如果做缓存（热数据）用 <code>allkeys-lru</code>；如果既做缓存又做持久存储（带 TTL 的才删）用 <code>volatile-lru</code>。Redis 是近似 LRU（随机采样对比），为了省内存。<br><strong>面试官追问：</strong> LFU（Least Frequently Used）策略解决了 LRU 什么痛点？（防止&quot;一次性扫描&quot;数据挤掉热数据）。</p><h3 id="_128-bigkey-治理" tabindex="-1"><a class="header-anchor" href="#_128-bigkey-治理"><span>128）BigKey 治理</span></a></h3><p><strong>面试官：</strong> 怎么发现 BigKey？删除 1GB 的 Hash Key 会发生什么？怎么优雅删除？<br><strong>候选人（要点）：</strong> 发现：<code>redis-cli --bigkeys</code> 或分析 RDB。直接 <code>DEL</code> 会阻塞主线程（STW）。优雅删：<code>UNLINK</code>（异步删除，Redis 4.0+）或 <code>HSCAN</code> 分批删。<br><strong>面试官追问：</strong> 大 Key 对网络和客户端有什么影响？（Head-of-line blocking，超时）。</p><h3 id="_129-hotkey-热点-key-治理" tabindex="-1"><a class="header-anchor" href="#_129-hotkey-热点-key-治理"><span>129）HotKey（热点 Key）治理</span></a></h3><p><strong>面试官：</strong> 比如&quot;某明星出轨&quot;，所有请求都在读同一个 Key，网卡打爆。怎么解？<br><strong>候选人（要点）：</strong></p><ol><li><strong>本地缓存</strong>（LocalCache）：应用层挡住。</li><li><strong>读写分离/副本</strong>：多 Slave 分担（不够）。</li><li><strong>热点散列</strong>：把 Key 复制多份（Key_1, Key_2...），客户端随机访问。<br><strong>面试官追问：</strong> 怎么自动发现热点 Key？（客户端统计 / Proxy 层统计 / Redis 4.0 <code>hotkeys</code> 参数）。</li></ol><h3 id="_130-rdb-vs-aof-灾难恢复实战" tabindex="-1"><a class="header-anchor" href="#_130-rdb-vs-aof-灾难恢复实战"><span>130）RDB vs AOF 灾难恢复实战</span></a></h3><p><strong>面试官：</strong> 机器断电，RDB 和 AOF 文件都损坏了怎么办？<br><strong>候选人（要点）：</strong> 先尝试 <code>redis-check-aof --fix</code> 修复（会丢部分数据）。生产环境通常开启 <strong>混合持久化</strong>（RDB 头 + AOF 尾），兼顾速度与安全。<br><strong>面试官追问：</strong> <code>bgrewriteaof</code> 期间主进程有写入，怎么保证 AOF 不丢？（AOF 重写缓冲区）。</p><h3 id="_131-主从复制-replication-原理" tabindex="-1"><a class="header-anchor" href="#_131-主从复制-replication-原理"><span>131）主从复制（Replication）原理</span></a></h3><p><strong>面试官：</strong> Slave 刚连上 Master 发生了什么？什么是 PSYNC？<br><strong>候选人（要点）：</strong> 全量复制：Master BGSAVE 生成 RDB -&gt; 发给 Slave -&gt; Slave 加载。PSYNC（部分复制）：断线重连后，根据 Offset 和 RunID 补发积压缓冲区（repl_backlog）里的数据。<br><strong>面试官追问：</strong> 如果 repl_backlog 太小会怎样？（频繁触发全量复制，死循环）。</p><h3 id="_132-sentinel-哨兵-选主逻辑" tabindex="-1"><a class="header-anchor" href="#_132-sentinel-哨兵-选主逻辑"><span>132）Sentinel（哨兵）选主逻辑</span></a></h3><p><strong>面试官：</strong> Master 挂了，哨兵怎么选出新 Master？<br><strong>候选人（要点）：</strong> 1) 过滤掉不健康的；2) 选优先级高的；3) 选复制偏移量（Offset）最大的（数据最全）；4) 选 RunID 最小的。<br><strong>面试官追问：</strong> 脑裂（Split-brain）是什么？怎么配置 <code>min-slaves-to-write</code> 防止数据丢失？</p><h3 id="_133-cluster-重定向与-hash-tag" tabindex="-1"><a class="header-anchor" href="#_133-cluster-重定向与-hash-tag"><span>133）Cluster 重定向与 Hash Tag</span></a></h3><p><strong>面试官：</strong> 客户端请求 Key，节点返回 <code>MOVED</code> 和 <code>ASK</code> 有什么区别？<br><strong>候选人（要点）：</strong> <code>MOVED</code>：槽（Slot）永久迁移了，客户端更新映射；<code>ASK</code>：槽正在迁移中（临时访问目标节点）。<br><strong>面试官追问：</strong> 怎么保证 <code>user:{100}:profile</code> 和 <code>user:{100}:orders</code> 落在同一个节点？（Hash Tag <code>{}</code>）。</p><h3 id="_134-client-side-caching-客户端缓存" tabindex="-1"><a class="header-anchor" href="#_134-client-side-caching-客户端缓存"><span>134）Client-side Caching（客户端缓存）</span></a></h3><p><strong>面试官：</strong> Redis 6.0 的客户端缓存是怎么保证一致性的？<br><strong>候选人（要点）：</strong> 服务端记录客户端访问了哪些 Key；当 Key 修改时，服务端给客户端发失效消息（Invalidation Message）；客户端收到后清空本地缓存。<br><strong>面试官追问：</strong> 广播模式（Broadcasting）的优缺点？（无需服务端记状态，但流量大）。</p><h3 id="_135-redis-事务-acid-假象" tabindex="-1"><a class="header-anchor" href="#_135-redis-事务-acid-假象"><span>135）Redis 事务（ACID 假象）</span></a></h3><p><strong>面试官：</strong> <code>MULTI</code> / <code>EXEC</code> 能保证 ACID 吗？如果中间一条命令报错，后面会执行吗？<br><strong>候选人（要点）：</strong> 语法错误（入队失败）会全体取消；运行时错误（如对 String 做 LPUSH）该条失败，后续<strong>继续执行</strong>。不支持回滚（No Rollback）。<br><strong>面试官追问：</strong> <code>WATCH</code> 命令是做什么的？（乐观锁，CAS）。</p><h3 id="_136-分布式锁-redlock-争议" tabindex="-1"><a class="header-anchor" href="#_136-分布式锁-redlock-争议"><span>136）分布式锁：Redlock 争议</span></a></h3><p><strong>面试官：</strong> Redlock 到底安全吗？NPC 问题（Network, Pause, Clock）指什么？<br><strong>候选人（要点）：</strong> 有争议。安全隐患：时钟跳变导致锁提前过期；GC 暂停导致锁过期但客户端以为持有。结论：对于追求绝对一致性的（如金融），Redlock 不够，请用 ZooKeeper/Etcd。对于一般业务，Redlock/单实例锁够用。<br><strong>面试官追问：</strong> Fencing Token 是什么？怎么解决锁过期后的并发写？</p><h3 id="_137-分布式锁-可重入性" tabindex="-1"><a class="header-anchor" href="#_137-分布式锁-可重入性"><span>137）分布式锁：可重入性</span></a></h3><p><strong>面试官：</strong> Redis 锁怎么实现可重入（同一个线程多次加锁）？<br><strong>候选人（要点）：</strong> Value 里存 <code>UUID:ThreadId</code>；Hash 结构存 <code>锁标识</code> 和 <code>重入计数</code>。加锁：key 存在且是自己，计数+1；解锁：计数-1，为 0 时 DEL。<br><strong>面试官追问：</strong> 可重入锁的 WatchDog 怎么处理？（只对顶层锁续期）。</p><h3 id="_138-分布式锁-惊群效应" tabindex="-1"><a class="header-anchor" href="#_138-分布式锁-惊群效应"><span>138）分布式锁：惊群效应</span></a></h3><p><strong>面试官：</strong> 1000 个线程抢锁，释放时怎么避免同时唤醒？<br><strong>候选人（要点）：</strong> Redis 锁通常是自旋（Spin）或休眠重试，不涉及 OS 级唤醒惊群。但高频轮询会打挂 Redis。优化：Pub/Sub 通知机制（Redisson 做法），释放时发消息，等待者收到才抢。<br><strong>面试官追问：</strong> Redisson 的 <code>tryLock</code> 等待机制原理？（Semaphore + PubSub）。</p><h3 id="_139-redisson-原理深度" tabindex="-1"><a class="header-anchor" href="#_139-redisson-原理深度"><span>139）Redisson 原理深度</span></a></h3><p><strong>面试官：</strong> Redisson 怎么实现&quot;锁续期&quot;？如果客户端宕机，看门狗会死锁吗？<br><strong>候选人（要点）：</strong> 客户端起一个 TimerTask（默认 10s），定期发 Lua 脚本续 TTL。如果客户端宕机，Timer 停了，续期停止，Redis 里的 Key 到期自动删除，不产生死锁。<br><strong>面试官追问：</strong> 业务手动把锁删了，看门狗还在跑怎么办？（Redisson 内部会维护锁状态，本地释放时同时取消 Timer）。</p><h3 id="_140-redis-内存碎片" tabindex="-1"><a class="header-anchor" href="#_140-redis-内存碎片"><span>140）Redis 内存碎片</span></a></h3><p><strong>面试官：</strong> <code>INFO memory</code> 里的 <code>mem_fragmentation_ratio</code> 高说明什么？怎么处理？<br><strong>候选人（要点）：</strong> 说明碎片率高（申请 1G，OS 分配 1.5G）。原因：频繁修改 Key 长度、过期删除。处理：重启（最快），或配置 <code>activedefrag</code> 自动整理（Redis 4.0+，耗 CPU）。<br><strong>面试官追问：</strong> 使用 Jemalloc 分配器比 glibc 好在哪？</p><h3 id="_141-redis-慢查询日志" tabindex="-1"><a class="header-anchor" href="#_141-redis-慢查询日志"><span>141）Redis 慢查询日志</span></a></h3><p><strong>面试官：</strong> 怎么抓取线上慢查询？<code>slowlog-log-slower-than</code> 设多少合适？<br><strong>候选人（要点）：</strong> <code>slowlog get 10</code>。阈值通常设 10ms 或 1ms（视业务敏感度）。注意：Slowlog 只记录执行时间，不含网络排队时间。<br><strong>面试官追问：</strong> 为什么有时候 Redis 很慢，但 Slowlog 是空的？（网络延迟、AOF 刷盘阻塞）。</p><h3 id="_142-redis-协议-resp" tabindex="-1"><a class="header-anchor" href="#_142-redis-协议-resp"><span>142）Redis 协议（RESP）</span></a></h3><p><strong>面试官：</strong> 为什么 Redis 自定义 RESP 协议而不用 JSON/HTTP？<br><strong>候选人（要点）：</strong> 解析极快（前缀长度读取）、人类可读（文本协议）、二进制安全（Bulk String）。<br><strong>面试官追问：</strong> 你能手写一个 <code>SET key val</code> 的 RESP 报文吗？（<code>*3\\r\\n$3\\r\\nSET\\r\\n...</code>）。</p><h3 id="_143-缓存预热" tabindex="-1"><a class="header-anchor" href="#_143-缓存预热"><span>143）缓存预热</span></a></h3><p><strong>面试官：</strong> 大促前怎么做缓存预热？<br><strong>候选人（要点）：</strong> 1) 脚本批量加载热数据；2) CDN 预热；3) 应用启动时预加载。<br><strong>面试官追问：</strong> 预热时怎么避免网络风暴？（分批、随机延迟）。</p><h3 id="_144-多级缓存架构" tabindex="-1"><a class="header-anchor" href="#_144-多级缓存架构"><span>144）多级缓存架构</span></a></h3><p><strong>面试官：</strong> 本地缓存（In-Process）+ Redis + DB，怎么保证一致性？<br><strong>候选人（要点）：</strong> 难保证强一致。变更时：改 DB -&gt; 发 MQ/PubSub -&gt; 各实例清除本地缓存 + 删 Redis。接受短时间不一致（TTL兜底）。<br><strong>面试官追问：</strong> 什么时候需要引入 Nginx 共享字典缓存？</p><h3 id="_145-redis-运维命令" tabindex="-1"><a class="header-anchor" href="#_145-redis-运维命令"><span>145）Redis 运维命令</span></a></h3><p><strong>面试官：</strong> <code>FLUSHALL</code>、<code>KEYS *</code> 在生产环境怎么禁掉？<br><strong>候选人（要点）：</strong> <code>redis.conf</code> 里 <code>rename-command FLUSHALL &quot;&quot;</code>。<br><strong>面试官追问：</strong> 怎么在不停止服务的情况下将 Redis 数据迁移到新集群？（主从同步 / <code>MIGRATE</code> / 第三方工具 redis-shake）。</p><h3 id="_146-codis-vs-redis-cluster" tabindex="-1"><a class="header-anchor" href="#_146-codis-vs-redis-cluster"><span>146）Codis vs Redis Cluster</span></a></h3><p><strong>面试官：</strong> 以前常用的 Codis 和官方 Cluster 区别？现在还用 Codis 吗？<br><strong>候选人（要点）：</strong> Codis 是中心化 Proxy 架构，运维简单但不支持部分命令；Cluster 去中心化，客户端直连。现在主流用 Cluster 或云厂商托管版。<br><strong>面试官追问：</strong> Proxy 架构（如 Twemproxy/Predixy）的好处？（客户端解耦，连接复用）。</p><h3 id="_147-redis-作为数据库的坑" tabindex="-1"><a class="header-anchor" href="#_147-redis-作为数据库的坑"><span>147）Redis 作为数据库的坑</span></a></h3><p><strong>面试官：</strong> 把 Redis 当主库（全量存储）用，有什么风险？<br><strong>候选人（要点）：</strong> 内存贵；数据可靠性弱（RDB/AOF 都有丢数据窗口）；复杂查询支持差；数据模型迁移困难。<br><strong>面试官追问：</strong> 有什么场景适合 Redis 当主库？（Session、非关键配置、临时验证码）。</p><h3 id="_148-list-作为消息队列的坑" tabindex="-1"><a class="header-anchor" href="#_148-list-作为消息队列的坑"><span>148）List 作为消息队列的坑</span></a></h3><p><strong>面试官：</strong> 用 <code>BLPOP</code> 做队列，消费者挂了消息会丢吗？怎么解决？<br><strong>候选人（要点）：</strong> 会丢（弹出即删除）。解决：<code>RPOPLPUSH</code>（原子弹出并推入备份队列），处理完再删备份。<br><strong>面试官追问：</strong> 只有 List 怎么做延时队列？（不行，得配合 ZSet）。</p><h3 id="_149-redis-脑裂与数据丢失" tabindex="-1"><a class="header-anchor" href="#_149-redis-脑裂与数据丢失"><span>149）Redis 脑裂与数据丢失</span></a></h3><p><strong>面试官：</strong> 哨兵模式下，Master 假死，Sentinel 选了新主，旧 Master 恢复了会怎样？<br><strong>候选人（要点）：</strong> 旧 Master 变成 Slave，同步新主数据，导致假死期间客户端写入旧主的数据<strong>全部丢失</strong>。<br><strong>面试官追问：</strong> 怎么减少这种丢失？（配置 <code>min-slaves-to-write</code>，少于 N 个从节点确认就不让写，牺牲可用性换一致性）。</p><h3 id="_150-redis-模块开发-remodule" tabindex="-1"><a class="header-anchor" href="#_150-redis-模块开发-remodule"><span>150）Redis 模块开发（ReModule）</span></a></h3><p><strong>面试官：</strong> 你知道 Redis 可以加载动态链接库扩展功能吗？举个例子。<br><strong>候选人（要点）：</strong> <code>loadmodule</code>。例子：RedisSearch（全文搜）、RedisJSON（原生 JSON 操作）、RedisGraph。<br><strong>面试官追问：</strong> 模块的性能风险？（可能阻塞主线程）。</p><h2 id="🟡-中级梯队-rabbitmq-可靠性与性能调优-151–180-1" tabindex="-1"><a class="header-anchor" href="#🟡-中级梯队-rabbitmq-可靠性与性能调优-151–180-1"><span>🟡 中级梯队：RabbitMQ 可靠性与性能调优（151–180）[1]</span></a></h2><h3 id="_151-rabbitmq-架构模式-镜像队列-vs-quorum-queues" tabindex="-1"><a class="header-anchor" href="#_151-rabbitmq-架构模式-镜像队列-vs-quorum-queues"><span>151）RabbitMQ 架构模式：镜像队列 vs Quorum Queues</span></a></h3><p><strong>面试官：</strong> 为什么 RabbitMQ 3.8+ 推荐用 Quorum Queues 代替镜像队列（Mirrored Queues）？<br><strong>候选人（要点）：</strong> 镜像队列同步效率低（全量同步）、网络分区处理差（脑裂风险）；Quorum Queues 基于 Raft 协议，只同步日志，支持大多数提交，性能和可靠性更好，天然支持毒消息处理。[2]<br><strong>面试官追问：</strong> 迁移到 Quorum Queues 有什么限制？（不支持 TTL、不支持排他队列、内存开销稍大）。</p><h3 id="_152-消息可靠性-publisher-confirm-原理" tabindex="-1"><a class="header-anchor" href="#_152-消息可靠性-publisher-confirm-原理"><span>152）消息可靠性：Publisher Confirm 原理</span></a></h3><p><strong>面试官：</strong> 开启 Publisher Confirm 后，Broker 什么时候发回 Ack？是落盘后吗？<br><strong>候选人（要点）：</strong> 普通消息：投递到所有匹配队列后（如果队列持久化则需落盘）；镜像消息：所有镜像接收/落盘后。这是异步的。<br><strong>面试官追问：</strong> 如果 Confirm 没收到（Nack），生产者应该怎么做？（重试发送，注意去重）。</p><h3 id="_153-消息可靠性-return-listener" tabindex="-1"><a class="header-anchor" href="#_153-消息可靠性-return-listener"><span>153）消息可靠性：Return Listener</span></a></h3><p><strong>面试官：</strong> 消息发到 Exchange 但找不到 Queue（RoutingKey 没配对），消息去哪了？怎么感知？<br><strong>候选人（要点）：</strong> 默认丢弃。开启 <code>Mandatory=true</code> 并注册 Return Listener，Broker 会把不可达消息退回给生产者。<br><strong>面试官追问：</strong> 备份交换机（Alternate Exchange）的作用？它和 Return Listener 谁优先级高？</p><h3 id="_154-消息积压-消费者扩容与预取" tabindex="-1"><a class="header-anchor" href="#_154-消息积压-消费者扩容与预取"><span>154）消息积压：消费者扩容与预取</span></a></h3><p><strong>面试官：</strong> 线上积压 100 万条，除了加机器，消费者参数 <code>prefetch_count</code> 怎么调？<br><strong>候选人（要点）：</strong> 调大 prefetch（如 100-500），配合多线程消费/批量消费，减少网络 ACK 交互频率；但不能太大导致单节点内存溢出或负载不均。<br><strong>面试官追问：</strong> 如果积压是因为某一条毒消息导致消费者无限崩溃重启，怎么救？</p><h3 id="_155-死信队列-dlx-循环引用" tabindex="-1"><a class="header-anchor" href="#_155-死信队列-dlx-循环引用"><span>155）死信队列（DLX）循环引用</span></a></h3><p><strong>面试官：</strong> 如果死信队列 TTL 过期后又转发回原队列，会发生什么？这种模式有什么用？<br><strong>候选人（要点）：</strong> 构成死循环。用途：实现<strong>延迟重试队列</strong>（消费失败 -&gt; 进死信等待 5s -&gt; 回原队列重试）。<br><strong>面试官追问：</strong> RabbitMQ 怎么识别&quot;这条消息重试了多少次&quot;？（查看 header 里的 <code>x-death</code> 数组）。</p><h3 id="_156-延迟队列实现对比" tabindex="-1"><a class="header-anchor" href="#_156-延迟队列实现对比"><span>156）延迟队列实现对比</span></a></h3><p><strong>面试官：</strong> <code>TTL + DLX</code> vs <code>rabbitmq-delayed-message-exchange</code> 插件，选哪个？<br><strong>候选人（要点）：</strong> 插件更方便（基于 Mnesia 表），支持任意延迟时间；TTL+DLX 需要建多个固定时间的死信级联。推荐插件，但注意插件在大数据量下性能较差（消息存在 RAM）。<br><strong>面试官追问：</strong> 为什么不推荐用应用层 <code>Task.Delay</code> 做延迟？（不持久、重启丢失、占内存）。</p><h3 id="_157-消息顺序性-sharding" tabindex="-1"><a class="header-anchor" href="#_157-消息顺序性-sharding"><span>157）消息顺序性：Sharding</span></a></h3><p><strong>面试官：</strong> 只有 1 个 Queue 吞吐量不够，多 Queue 又乱序，怎么解？<br><strong>候选人（要点）：</strong> 分片（Sharding）。使用 Consistent Hash Exchange 或应用层 Hash，把同一 <code>OrderId</code> 的消息总是路由到同一个 Queue，该 Queue 对应一个消费者，实现局部顺序 + 并行扩容。<br><strong>面试官追问：</strong> 扩容增加 Queue 时，旧消息顺序会乱吗？怎么平滑迁移？</p><h3 id="_158-rabbitmq-内存控制-memory-high-watermark" tabindex="-1"><a class="header-anchor" href="#_158-rabbitmq-内存控制-memory-high-watermark"><span>158）RabbitMQ 内存控制（Memory High Watermark）</span></a></h3><p><strong>面试官：</strong> RabbitMQ 内存告警（阻塞生产者）的阈值默认是多少？达到阈值会发生什么？<br><strong>候选人（要点）：</strong> 默认 40% 物理内存。达到后会停止接收新消息（Connection Blocked），直到内存水位下降（GC 或刷盘）。<br><strong>面试官追问：</strong> 怎么避免这种情况？（开启 Lazy Queue、及时消费、调大阈值但风险增加）。</p><h3 id="_159-lazy-queue-惰性队列" tabindex="-1"><a class="header-anchor" href="#_159-lazy-queue-惰性队列"><span>159）Lazy Queue（惰性队列）</span></a></h3><p><strong>面试官：</strong> Lazy Queue 和普通队列的区别？什么时候必须用？<br><strong>候选人（要点）：</strong> 普通队列尽量存内存；Lazy Queue 直接存磁盘（只在内存留索引）。适合：大量积压场景、冷备队列、内存紧张的环境。<br><strong>面试官追问：</strong> Lazy Queue 的性能代价？（磁盘 IO 增加，延迟稍高）。</p><h3 id="_160-rabbitmq-集群-普通集群-vs-镜像集群" tabindex="-1"><a class="header-anchor" href="#_160-rabbitmq-集群-普通集群-vs-镜像集群"><span>160）RabbitMQ 集群：普通集群 vs 镜像集群</span></a></h3><p><strong>面试官：</strong> 普通集群模式下，队列数据是在所有节点都有吗？<br><strong>候选人（要点）：</strong> 不是。元数据（Exchange/Queue 定义）全量同步，但消息实体只在创建队列的节点（Owner Node）。其他节点只转发请求。<br><strong>面试官追问：</strong> 这种模式有什么单点风险？镜像集群是怎么解决的？</p><h3 id="_161-脑裂-network-partition-处理" tabindex="-1"><a class="header-anchor" href="#_161-脑裂-network-partition-处理"><span>161）脑裂（Network Partition）处理</span></a></h3><p><strong>面试官：</strong> RabbitMQ 集群发生网络分区（脑裂）时，默认行为是什么？怎么配置自动恢复？<br><strong>候选人（要点）：</strong> 默认 <code>ignore</code>（各分区独立写入，合并时数据冲突丢失）。推荐配置 <code>pause_minority</code>（暂停少数派节点）或 <code>autoheal</code>（胜者为王，丢弃败者数据）。可靠性要求高选 <code>pause_minority</code>。<br><strong>面试官追问：</strong> CAP 理论里 RabbitMQ 是 AP 还是 CP？（镜像队列偏 AP，Quorum Queues 偏 CP）。</p><h3 id="_162-消息幂等-全局-id-生成" tabindex="-1"><a class="header-anchor" href="#_162-消息幂等-全局-id-生成"><span>162）消息幂等：全局 ID 生成</span></a></h3><p><strong>面试官：</strong> 消息体里没有业务唯一键（如日志），怎么做幂等？<br><strong>候选人（要点）：</strong> 生产者生成 UUID / Snowflake ID 放入 Message Properties (<code>MessageId</code>)；消费者根据此 ID 去重。不要依赖 Broker 生成的 ID（那个无法跨重试保持一致）。<br><strong>面试官追问：</strong> 消费者去重表的数据量太大会影响性能吗？怎么定期清理？</p><h3 id="_163-优先级队列-priority-queue" tabindex="-1"><a class="header-anchor" href="#_163-优先级队列-priority-queue"><span>163）优先级队列（Priority Queue）</span></a></h3><p><strong>面试官：</strong> 怎么实现 VIP 用户消息优先处理？RabbitMQ 支持插队吗？<br><strong>候选人（要点）：</strong> 支持 <code>x-max-priority</code> 参数定义优先级队列。发送时设置 <code>Priority</code> 属性。高优先级优先被消费。<br><strong>面试官追问：</strong> 优先级队列的性能损耗？如果队列一直没积压，优先级生效吗？（不生效，先进先出）。</p><h3 id="_164-rpc-模式-request-reply" tabindex="-1"><a class="header-anchor" href="#_164-rpc-模式-request-reply"><span>164）RPC 模式（Request-Reply）</span></a></h3><p><strong>面试官：</strong> 用 RabbitMQ 做 RPC（同步调用）的原理？<br><strong>候选人（要点）：</strong> 生产者发消息带 <code>ReplyTo</code> 队列名和 <code>CorrelationId</code>；消费者处理完把结果发回 <code>ReplyTo</code> 队列；生产者阻塞等待该队列响应。<br><strong>面试官追问：</strong> 如果 RPC 超时了怎么处理？CorrelationId 的作用？</p><h3 id="_165-federation-与-shovel" tabindex="-1"><a class="header-anchor" href="#_165-federation-与-shovel"><span>165）Federation 与 Shovel</span></a></h3><p><strong>面试官：</strong> 怎么实现跨机房/跨区域的消息同步？<br><strong>候选人（要点）：</strong></p><ul><li><strong>Federation</strong>：逻辑连接，下游主动拉取上游消息，适合跨 WAN 扩展。</li><li><strong>Shovel</strong>：类似转发器，从源队列搬运到目的队列，更灵活（支持不同 Broker 类型）。<br><strong>面试官追问：</strong> Federation 环形拓扑会导致消息无限循环吗？（不会，有跳数限制）。</li></ul><h3 id="_166-masstransit-cap-框架" tabindex="-1"><a class="header-anchor" href="#_166-masstransit-cap-框架"><span>166）MassTransit / CAP 框架</span></a></h3><p><strong>面试官：</strong> 在 .NET 里直接用 RabbitMQ.Client 还是用封装框架（MassTransit/CAP）？为什么？<br><strong>候选人（要点）：</strong> 推荐封装框架。MassTransit 封装了重试、熔断、序列化、Saga；CAP 封装了本地消息表（Outbox）保证最终一致性。原生 Client 容易写出 Bug（如连接复用、异常处理不当）。[3]<br><strong>面试官追问：</strong> CAP 的工作原理？它怎么保证&quot;数据库提交成功，消息一定发出&quot;？</p><h3 id="_167-exchange-to-exchange-binding" tabindex="-1"><a class="header-anchor" href="#_167-exchange-to-exchange-binding"><span>167）Exchange to Exchange Binding</span></a></h3><p><strong>面试官：</strong> 交换机能绑定交换机吗？有什么用？<br><strong>候选人（要点）：</strong> 能。用于构建复杂路由拓扑，减少重复绑定。例如：一个 <code>LogExchange</code> 广播给 <code>FileExchange</code> 和 <code>DbExchange</code>，解耦不同类型的处理管道。<br><strong>面试官追问：</strong> 这样会增加路由延迟吗？</p><h3 id="_168-connection-vs-channel" tabindex="-1"><a class="header-anchor" href="#_168-connection-vs-channel"><span>168）Connection vs Channel</span></a></h3><p><strong>面试官：</strong> 一个应用该创建多少 Connection？多少 Channel？<br><strong>候选人（要点）：</strong> Connection 对应 TCP 连接，很重，整个应用应单例（复用）；Channel 对应虚拟会话，轻量，<strong>非线程安全</strong>，每个线程/并发任务应独占一个 Channel。<br><strong>面试官追问：</strong> Channel 也能复用吗？多线程共用一个 Channel 会报什么错？</p><h3 id="_169-prefetch-count-调优" tabindex="-1"><a class="header-anchor" href="#_169-prefetch-count-调优"><span>169）Prefetch Count 调优</span></a></h3><p><strong>面试官：</strong> <code>BasicQos(prefetch=1)</code> 是什么意思？高吞吐场景设多少？<br><strong>候选人（要点）：</strong> 设为 1 表示&quot;处理完 1 个才发下 1 个&quot;（公平分发），适合耗时任务。高吞吐场景应设大（如 100），配合批量 ACK，减少网络 RTT 等待。<br><strong>面试官追问：</strong> 如果消费者是多线程并发处理，prefetch 应该怎么设？（线程数 * N）。</p><h3 id="_170-消息体大小限制" tabindex="-1"><a class="header-anchor" href="#_170-消息体大小限制"><span>170）消息体大小限制</span></a></h3><p><strong>面试官：</strong> 能用 MQ 传 100MB 的文件吗？最大限制是多少？<br><strong>候选人（要点）：</strong> 理论无硬限（受内存限制），但建议 &lt; 128KB。大文件应传 URL（对象存储地址），MQ 只传引用。大消息会阻塞带宽，导致心跳超时，引发连接断开。<br><strong>面试官追问：</strong> 如果必须传大文本，怎么优化？（Gzip 压缩）。</p><h3 id="_171-rabbitmq-监控指标" tabindex="-1"><a class="header-anchor" href="#_171-rabbitmq-监控指标"><span>171）RabbitMQ 监控指标</span></a></h3><p><strong>面试官：</strong> 线上出问题，你主要看哪些监控指标？<br><strong>候选人（要点）：</strong></p><ol><li><strong>Queue Depth</strong>（堆积量）。</li><li><strong>Unacked Messages</strong>（正在处理量，高说明处理慢或忘 ACK）。</li><li><strong>Connection/Channel Count</strong>（是否有泄漏）。</li><li><strong>Disk/Memory Alarms</strong>。<br><strong>面试官追问：</strong> Ready 很多但 Unacked 为 0，说明什么？（消费者挂了或没订阅）。</li></ol><h3 id="_172-消费者限流-rate-limiting" tabindex="-1"><a class="header-anchor" href="#_172-消费者限流-rate-limiting"><span>172）消费者限流（Rate Limiting）</span></a></h3><p><strong>面试官：</strong> 怎么限制消费速度，防止把下游 DB 打挂？<br><strong>候选人（要点）：</strong> 设置 <code>prefetch_count</code>；在消费者业务逻辑里加令牌桶（RateLimiter）；或者简单地 <code>Thread.Sleep</code>（不推荐）。<br><strong>面试官追问：</strong> 暂停消费（StopConsuming）怎么实现？（<code>BasicCancel</code> 取消订阅）。</p><h3 id="_173-rabbitmq-插件机制" tabindex="-1"><a class="header-anchor" href="#_173-rabbitmq-插件机制"><span>173）RabbitMQ 插件机制</span></a></h3><p><strong>面试官：</strong> 除了延迟插件，还用过什么插件？Management 插件是默认开的吗？<br><strong>候选人（要点）：</strong> Management（管理界面）、Sharding（分片）、Consistent Hash。生产环境通常需要显式启用。<br><strong>面试官追问：</strong> 插件会影响性能吗？（会，尤其是涉及持久化或复杂逻辑的）。</p><h3 id="_174-临时队列-temporary-queue" tabindex="-1"><a class="header-anchor" href="#_174-临时队列-temporary-queue"><span>174）临时队列（Temporary Queue）</span></a></h3><p><strong>面试官：</strong> RPC 里的 <code>ReplyTo</code> 队列通常是什么类型的？<br><strong>候选人（要点）：</strong> 独占（Exclusive）、自动删除（Auto-delete）、匿名队列（服务端生成随机名）。连接断开即销毁。<br><strong>面试官追问：</strong> 如果客户端崩溃，临时队列没删，会怎样？（占用 Broker 资源，直到重启）。</p><h3 id="_175-trace-日志-firehose" tabindex="-1"><a class="header-anchor" href="#_175-trace-日志-firehose"><span>175）Trace 日志（Firehose）</span></a></h3><p><strong>面试官：</strong> 怎么抓取进出 Broker 的每一条消息进行调试？<br><strong>候选人（要点）：</strong> 开启 Firehose Tracer；它会把所有消息复制一份发到 <code>amq.rabbitmq.trace</code> 交换机。注意：生产开启会严重影响性能。<br><strong>面试官追问：</strong> GUI 版的 tracing 工具是什么？</p><h3 id="_176-消息版本控制" tabindex="-1"><a class="header-anchor" href="#_176-消息版本控制"><span>176）消息版本控制</span></a></h3><p><strong>面试官：</strong> 消费者代码升级了，消息格式变了，怎么做平滑发布？<br><strong>候选人（要点）：</strong></p><ol><li>消息体带版本号 <code>v=2</code>。</li><li>消费者兼容旧版本（宽容读取）。</li><li>蓝绿部署：新消费者绑定新队列，Exchange 路由切换。<br><strong>面试官追问：</strong> Protobuf 相比 JSON 在版本兼容上的优势？</li></ol><h3 id="_177-事务消息-tx" tabindex="-1"><a class="header-anchor" href="#_177-事务消息-tx"><span>177）事务消息（TX）</span></a></h3><p><strong>面试官：</strong> RabbitMQ 支持事务吗（<code>txSelect</code>, <code>txCommit</code>）？性能怎么样？<br><strong>候选人（要点）：</strong> 支持 AMQP 协议级事务，但性能极差（同步阻塞），降低吞吐量 2-10 倍。基本不用，用 Publisher Confirm 代替。<br><strong>面试官追问：</strong> 为什么 Confirm 比事务快？（异步流式）。</p><h3 id="_178-vhost-虚拟主机" tabindex="-1"><a class="header-anchor" href="#_178-vhost-虚拟主机"><span>178）vhost（虚拟主机）</span></a></h3><p><strong>面试官：</strong> vhost 的作用？多租户怎么隔离？<br><strong>候选人（要点）：</strong> 逻辑隔离（类似 Namespace），拥有独立的 Exchange/Queue/权限。不同环境（Dev/Test）或不同租户应使用不同 vhost。<br><strong>面试官追问：</strong> vhost 之间能路由消息吗？（不能，完全隔离）。</p><h3 id="_179-erlang-cookie" tabindex="-1"><a class="header-anchor" href="#_179-erlang-cookie"><span>179）Erlang Cookie</span></a></h3><p><strong>面试官：</strong> 集群搭建时 Erlang Cookie 不一致会报什么错？<br><strong>候选人（要点）：</strong> 认证失败，节点无法通信（Connection refused / Authentication failed）。必须保证所有节点 Cookie 文件内容完全一致。<br><strong>面试官追问：</strong> 只有 Cookie 一致就能组网吗？（还需要主机名解析正常）。</p><h3 id="_180-rabbitmq-运维-节点下线" tabindex="-1"><a class="header-anchor" href="#_180-rabbitmq-运维-节点下线"><span>180）RabbitMQ 运维：节点下线</span></a></h3><p><strong>面试官：</strong> 怎么优雅下线一个集群节点进行维护？<br><strong>候选人（要点）：</strong></p><ol><li><code>rabbitmqctl stop_app</code>。</li><li>检查队列镜像同步状态，确保数据已迁移到其他节点。</li><li>从负载均衡摘除。<br><strong>面试官追问：</strong> 如果直接 kill 进程，Quorum Queue 会受影响吗？（Raft 会重新选主，短暂不可用但数据安全）。</li></ol>`,374)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};